export interface GlossarySourceEntry { sigle: string; nom: string; def: string; guide?: string; }
export interface GlossarySourceSection { titre: string; accent: string; entries: GlossarySourceEntry[]; }
export type GlossaryGraphLinkKind = 'article' | 'guide' | 'dataset' | 'signal' | 'source' | 'methodology';
export interface GlossaryGraphLink {
  label: string;
  href: string;
  detail?: string;
  kind?: GlossaryGraphLinkKind;
}
export interface GlossaryKnowledgeGraph {
  intuition?: string;
  formula?: string;
  whyNow?: string;
  articles?: GlossaryGraphLink[];
  guides?: GlossaryGraphLink[];
  datasets?: GlossaryGraphLink[];
  signals?: GlossaryGraphLink[];
  sources?: GlossaryGraphLink[];
  related?: string[];
}

const rawGlossarySections: GlossarySourceSection[] = [
  {
    titre: 'Macro & banques centrales',
    accent: 'var(--color-signal)',
    entries: [
      { sigle: 'CPI', nom: 'Consumer Price Index', def: "Indice des prix à la consommation américain, publié chaque mois par le BLS. Mesure la variation d'un panier fixe de biens et services des ménages urbains. Le plus suivi des marchés, mais la Fed cible le PCE. Équivalent de l'IPC français.", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'IPC', nom: 'Indice des prix à la consommation', def: "Mesure française et européenne de l'inflation vécue par les ménages. Pendant du CPI américain." },
      { sigle: 'Core CPI', nom: 'Inflation sous-jacente', def: "CPI hors alimentation et énergie, les deux postes les plus volatils. Isole la tendance de fond des prix, suivie de près par la Fed et les marchés pour juger de la persistance de l'inflation.", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'Supercore', nom: 'Services hors logement', def: "Services hors énergie et hors logement, brique d'inflation la plus liée aux salaires et la plus collante. Mise en avant par la Fed pendant le resserrement de 2022-2023. Le BLS publie l'agrégat proche « services hors loyers du logement »." , guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'OER', nom: 'Loyer imputé aux propriétaires', def: "Owners' equivalent rent : loyer que les propriétaires devraient payer pour habiter leur propre logement. Plus gros poste du CPI, environ 26 %. Mesuré par équivalence locative depuis 1987, il réagit avec retard aux loyers de marché.", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'CPI-W', nom: 'CPI for Urban Wage Earners', def: "Variante du CPI restreinte aux ménages d'ouvriers et d'employés, environ 30 % de la population. Sert de base légale à l'indexation des prestations de la Sécurité sociale (COLA).", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'C-CPI-U', nom: 'Chained CPI', def: "Version chaînée du CPI qui intègre les substitutions des consommateurs entre catégories. Croît un peu moins vite que le CPI classique. Publiée en provisoire puis révisée trimestriellement.", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'COLA', nom: 'Cost-of-Living Adjustment', def: "Revalorisation annuelle des prestations de la Sécurité sociale américaine, indexée sur le CPI-W. Relie directement la mesure de l'inflation au revenu de dizaines de millions de retraités.", guide: 'lire-le-cpi-inflation-us' },
      { sigle: 'M1', nom: 'Agrégat monétaire étroit', def: "Mesure la plus liquide de la monnaie selon la Fed : monnaie fiduciaire, dépôts à vue et, depuis mai 2020, les autres dépôts liquides dont l'épargne. Incluse dans la M2." },
      { sigle: 'M2', nom: 'Agrégat monétaire large', def: "Agrégat de la Fed (communiqué H.6) égal à la M1 plus les dépôts à terme de petit montant et les fonds monétaires de détail. Mesure le stock de monnaie et de quasi-monnaie détenu par le public non bancaire. Souvent lu comme baromètre de liquidité.", guide: 'm2-masse-monetaire-risk-on' },
      { sigle: 'MMF', nom: 'Money market fund', def: "Fonds monétaire : placement collectif en titres courts et liquides. Les parts de fonds monétaires de détail entrent dans la M2. Leur gonflement peut traduire un repli vers la sécurité plutôt qu'un appétit pour le risque.", guide: '/guides/lire-les-fonds-monetaires/' },
      { sigle: 'Vélocité', nom: 'Vélocité de la monnaie', def: "Vitesse à laquelle une unité de monnaie change de mains, soit le revenu nominal rapporté à la masse monétaire. Si la vélocité baisse, une hausse de la M2 peut ne nourrir ni l'inflation ni les marchés." },
      { sigle: 'PTF', nom: 'Productivité totale des facteurs', def: "Part de la croissance qui ne s'explique ni par plus de travail ni par plus de capital, mais par une meilleure efficacité (technologie, organisation). Mesure résiduelle et centrale du progrès technique. L'estimation d'Acemoglu chiffre l'apport de l'IA à au plus 0,5 à 0,66 % de PTF sur dix ans." },
      { sigle: 'Paradoxe de Solow', nom: 'Solow paradox', def: "Constat de Robert Solow en 1987, « on voit l'âge informatique partout sauf dans les statistiques de productivité » : le décalage entre des gains technologiques visibles au niveau des tâches et un effet longtemps introuvable dans la productivité agrégée. Réapparu avec l'IA générative." },
      { sigle: 'GPU', nom: 'Graphics Processing Unit', def: "Processeur graphique massivement parallèle. Dans l'IA, le GPU devient un accélérateur de calcul : il exécute beaucoup d'opérations simples en parallèle et déplace la contrainte vers mémoire, réseau, packaging et énergie." },
      { sigle: 'EUV', nom: 'Extreme ultraviolet lithography', def: "Lithographie à ultraviolets extrêmes, utilisée pour imprimer les couches les plus complexes des puces avancées avec une lumière de 13,5 nm. Goulet industriel majeur car elle combine optique, vide, métrologie, logiciels et chaîne de fournisseurs spécialisée." },
      { sigle: 'Fonderie', nom: 'Dedicated IC foundry', def: "Fabricant contractuel de semi-conducteurs qui produit les puces conçues par d'autres. Une fonderie avancée vend de la capacité qualifiée, du rendement industriel et une feuille de route de noeuds, pas seulement des wafers." },
      { sigle: 'HBM', nom: 'High Bandwidth Memory', def: "Mémoire DRAM empilée à très large bande passante, placée près d'un accélérateur pour nourrir le calcul en données. Dans l'IA, elle transforme la mémoire en goulet de packaging et d'approvisionnement." },
      { sigle: 'Packaging avancé', nom: 'Advanced packaging', def: "Ensemble des techniques d'assemblage qui rapprochent plusieurs puces, mémoires et interconnexions dans un même module. Il devient critique quand la performance dépend autant du déplacement des données que du calcul brut." },
      { sigle: 'Fabless', nom: 'Concepteur sans usine', def: "Modèle d'entreprise qui conçoit des puces mais confie leur fabrication à une fonderie. Il sépare la propriété intellectuelle et le logiciel de la charge industrielle des fabs." },
      { sigle: 'Prime de terme', nom: 'Term premium', def: "Supplément de rendement qu'un investisseur exige pour détenir une obligation longue plutôt que d'enchaîner des placements courts, en compensation du risque de taux, d'inflation et d'offre de dette. Estimée par le modèle ACM de la Fed de New York. Négative ou nulle pendant une décennie, elle est repassée en positif en 2026, sans atteindre sa moyenne historique de long terme.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Duration', nom: 'Sensibilité aux taux', def: "Mesure de la sensibilité du prix d'une obligation à une variation de taux. Plus la duration est élevée, plus une hausse de rendement détruit de valeur de marché. Elle transforme une tension sur les taux longs en risque de bilan pour les porteurs de dette longue.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Adjudication', nom: 'Treasury auction', def: "Vente aux enchères par laquelle le Trésor américain émet sa dette. Enchère à prix unique : les soumissionnaires proposent des rendements et tous les gagnants paient le rendement qui solde l'émission. Sa lecture repose sur le bid-to-cover, le tail et la part des primary dealers.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Bid-to-cover', nom: 'Ratio de couverture', def: "Rapport entre le total des offres reçues à une adjudication et le montant vendu. Signal de volume de la demande : au-dessus de 2, l'appétit est jugé solide ; en dessous, faible.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Tail', nom: "Queue d'adjudication", def: "Écart entre le rendement qui solde une adjudication et le rendement anticipé juste avant sur le marché « When Issued ». Un tail positif signale que le Trésor a dû concéder un rendement plus élevé que prévu pour écouler son papier, donc une demande plus molle qu'espéré. Quelques dixièmes de point de base suffisent à alerter les marchés.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'When Issued', nom: 'Marché « quand émis »', def: "Marché à terme informel où une obligation du Trésor se négocie entre son annonce et son émission effective. Son rendement sert de référence pour juger le résultat de l'enchère : l'écart avec le taux adjugé donne le tail.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Soumissionnaires indirects', nom: 'Indirect bidders', def: "Catégorie d'acheteurs à une adjudication du Trésor passant par un intermédiaire, utilisée comme approximation de la demande étrangère : banques centrales, fonds souverains et institutions internationales. Une part indirecte élevée rassure sur l'appétit des investisseurs hors États-Unis.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Primary dealer', nom: 'Teneur de marché primaire', def: "Banque désignée par la Réserve fédérale de New York, tenue de participer à chaque adjudication du Trésor et de tenir le marché secondaire. Une vingtaine au total. Un dealer takedown élevé, la part revenant aux dealers, signale une demande finale faible.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'Courbe des taux', nom: 'Yield curve', def: "Ensemble des rendements des titres d'État selon leur maturité. Normalement croissante ; son inversion, taux courts au-dessus des taux longs, a précédé chacune des huit dernières récessions américaines. Sa pente informe autant que son niveau.", guide: '/guides/lire-le-marche-des-treasuries/' },
      { sigle: 'CBO', nom: 'Congressional Budget Office', def: "Agence budgétaire indépendante et non partisane du Congrès américain, créée en 1974. Elle ne recommande aucune politique mais en chiffre les conséquences. Ses projections servent de référence commune, sous l'hypothèse du droit en vigueur.", guide: '/guides/lire-les-previsions-du-cbo/' },
      { sigle: 'Baseline budgétaire', nom: 'Budget baseline', def: "Projection du CBO des recettes, dépenses et déficits sur dix ans sous l'hypothèse que le droit en vigueur ne change pas. Repère, et non prévision : ses conventions (dispositions expirantes supposées expirer, dépenses discrétionnaires indexées) produisent des effets contre-intuitifs.", guide: '/guides/lire-les-previsions-du-cbo/' },
      { sigle: 'Déficit primaire', nom: 'Primary deficit', def: "Déficit budgétaire hors charge d'intérêt de la dette. Il distingue la dépense courante en excès du coût de la dette passée : un déficit tiré par les intérêts signale un problème de stock, un déficit primaire un problème de politique budgétaire courante.", guide: '/guides/lire-les-previsions-du-cbo/' },
      { sigle: 'Dominance fiscale', nom: 'Fiscal dominance', def: "Situation où le poids de la dette publique contraint la politique monétaire : la banque centrale hésite à monter ou à maintenir des taux élevés de peur de rendre la dette insoutenable, laissant l'inflation en éroder la valeur. L'inverse d'une banque centrale libre de ses choix." },
      { sigle: 'MOVE', nom: 'Merrill Lynch Option Volatility Estimate', def: "Indice de la volatilité implicite du marché des obligations d'État américaines, l'équivalent obligataire du VIX actions. Exprimé en points de base ; sous 80, marché calme, au-dessus de 120, tension. Un MOVE élevé signale du stress sur les taux et sert d'approximation de la prime de terme.", guide: '/guides/lire-la-volatilite-vix-move/' },
      { sigle: 'VIX', nom: 'CBOE Volatility Index', def: "Indice de la volatilité implicite attendue du S&P 500 sur 30 jours, calculé par le Cboe à partir des options, exprimé en pourcentage annualisé. Surnommé « indice de la peur » : il bondit dans les chutes de marché. Moyenne de long terme autour de 19-20 ; sous 15, complaisance ; au-delà de 30, tension.", guide: '/guides/lire-la-volatilite-vix-move/' },
      { sigle: 'VVIX', nom: 'Volatilité de la volatilité', def: "Indice mesurant la volatilité implicite des options sur le VIX lui-même. Un VVIX élevé alors que le VIX est bas révèle une nervosité tapie sous la surface, des investisseurs qui se couvrent contre un retournement soudain.", guide: '/guides/lire-la-volatilite-vix-move/' },
      { sigle: 'PIB', nom: 'Produit intérieur brut', def: "Valeur totale des biens et services produits dans un pays sur une période. Mesure de référence de l'activité économique." },
      { sigle: 'LGFV', nom: 'Local Government Financing Vehicle', def: "Véhicule de financement des collectivités locales chinoises : société ad hoc qui emprunte en gageant des terrains publics et se rembourse grâce aux cessions foncières. Pilier du financement local pendant deux décennies, fragilisé par l'effondrement immobilier qui a tari les recettes foncières. Sa dette, en partie hors bilan, est estimée entre 14 800 et 58 000 milliards de yuans selon les sources." },
      { sigle: 'Trois lignes rouges', nom: 'Three red lines', def: "Dispositif prudentiel imposé par Pékin en 2020 pour brider l'endettement des promoteurs immobiliers, via trois ratios financiers plafonnés (dette sur actifs, dette nette sur fonds propres, trésorerie sur dette à court terme). Déclencheur assumé du dégonflement de la bulle et de la vague de défauts qui a suivi." },
      { sigle: 'BCE', nom: 'Banque centrale européenne', def: "Institution qui conduit la politique monétaire de la zone euro : fixation des taux directeurs, contrôle de l'inflation." },
      { sigle: 'IPCH', nom: 'Indice des prix à la consommation harmonisé', def: "Mesure d'inflation harmonisée entre États membres de l'UE (HICP en anglais), calculée selon une méthodologie commune par Eurostat. C'est l'indice que la BCE cible pour sa stabilité des prix à 2 %." },
      { sigle: 'RTGS', nom: 'Real-time gross settlement', def: "Système de règlement brut en temps réel : chaque virement de gros montant est réglé individuellement et immédiatement en monnaie de banque centrale, sans compensation nette. Colonne vertébrale des paiements interbancaires (TARGET en zone euro, BOK-Wire+ en Corée)." },
      { sigle: 'Unicité de la monnaie', nom: 'Singleness of money', def: "Principe selon lequel toutes les formes de monnaie s'échangent au pair : un euro en dépôt bancaire vaut un euro en billet ou en monnaie de banque centrale, quel que soit son support. Ancrée par la monnaie de banque centrale, sa préservation est l'enjeu central de la tokenisation des dépôts." },
      { sigle: 'BoJ', nom: 'Bank of Japan', def: "Banque centrale du Japon. Fixe la politique monétaire japonaise, pilote les achats ou ventes d'actifs et peut agir comme agent opérationnel lors d'interventions de change décidées par le ministère des Finances." },
      { sigle: 'MoF', nom: 'Ministry of Finance Japan', def: "Ministère japonais des Finances. Autorité responsable de la politique de change et des décisions d'intervention sur le yen." },
      { sigle: 'Intervention de change', nom: 'FX intervention', def: "Achat ou vente de devises par une autorité publique pour peser sur le cours de sa monnaie. Au Japon, la décision revient au ministère des Finances, la BoJ exécute. Efficace pour casser une dynamique spéculative à court terme, rarement pour inverser une tendance portée par un écart de taux d'intérêt. Une intervention coordonnée entre plusieurs banques centrales a bien plus de poids qu'une action unilatérale.", guide: '/guides/lire-le-dollar-dxy-cross-currency-basis/' },
      { sigle: 'JGB', nom: 'Japanese Government Bond', def: "Obligation d'État japonaise. Rapporté au PIB, le stock de dette souveraine le plus lourd du monde développé. Longtemps maintenu à des rendements proches de zéro par la BoJ, encore premier détenteur avec une part tout juste repassée sous les 50 % du marché début 2026. La remontée de ses taux longs rogne l'avantage du yen carry et peut rapatrier l'épargne japonaise placée à l'étranger." },
      { sigle: 'YCC', nom: 'Yield Curve Control', def: "Contrôle de la courbe des taux : politique par laquelle la BoJ a plafonné le rendement du JGB à 10 ans en achetant sans limite, de 2016 jusqu'à son démantèlement en 2024. Reste l'instrument de dernier recours si les taux longs dérapent, au prix d'un gonflement du bilan et d'une pression baissière sur le yen." },
      { sigle: 'FMI', nom: 'Fonds monétaire international', def: "Institution multilatérale qui surveille le système monétaire mondial et prête aux États en difficulté de balance des paiements." },
      { sigle: 'BIS', nom: 'Bank for International Settlements', def: "Banque des règlements internationaux, à Bâle. La « banque centrale des banques centrales », référence pour les statistiques bancaires et de dette mondiales." },
      { sigle: 'ADB', nom: 'Asian Development Bank', def: "Banque asiatique de développement, à Manille. Référence pour les prévisions de croissance et d'inflation de la région Asie-Pacifique." },
      { sigle: 'OAT', nom: 'Obligation assimilable du Trésor', def: "Titre de dette émis par l'État français à moyen et long terme. Son taux sert de référence au coût d'emprunt de la France." },
      { sigle: 'Gilt', nom: 'Obligation souveraine britannique', def: "Titre de dette émis par le Trésor britannique. Marché central pour le financement du Royaume-Uni, les fonds de pension, les assureurs et les stratégies de taux financées en repo." },
      { sigle: 'INSEE', nom: "Institut national de la statistique et des études économiques", def: "Producteur officiel des statistiques économiques et démographiques françaises (inflation, croissance, emploi)." },
      { sigle: 'EIA', nom: 'Energy Information Administration', def: "Agence statistique du département américain de l'Énergie. Référence pour les données pétrole, gaz et énergie." },
      { sigle: 'IEA', nom: 'International Energy Agency', def: "Agence internationale de l'énergie, basée à Paris. Analyses et projections sur les marchés énergétiques mondiaux. Coordonne les libérations de stocks d'urgence de ses membres, comme les 400 millions de barils de mars 2026, la plus grande de son histoire." },
      { sigle: 'Règle des 90 jours', nom: 'Obligation de stocks IEA', def: "Engagement de chaque pays membre de l'Agence internationale de l'énergie de détenir des stocks pétroliers d'urgence équivalant à au moins 90 jours de ses importations nettes. Un pays exportateur net, comme les États-Unis depuis la fin des années 2010, respecte la règle même avec une réserve stratégique basse, ce qui change le sens de son coussin." },
      { sigle: 'FOMC', nom: 'Federal Open Market Committee', def: "Comité de politique monétaire de la Fed, qui fixe les taux directeurs. Se réunit huit fois par an, dont quatre réunions accompagnées de projections.", guide: 'lire-le-dot-plot-sep' },
      { sigle: 'SEP', nom: 'Summary of Economic Projections', def: "Projections trimestrielles des membres du FOMC (croissance, chômage, inflation, taux), publiées en mars, juin, septembre et décembre. Inclut le fameux dot plot, le nuage de points où chaque membre situe le taux qu'il juge approprié.", guide: 'lire-le-dot-plot-sep' },
      { sigle: 'Dot plot', nom: 'Nuage de points', def: "Graphique du SEP où chaque point situe le taux directeur qu'un participant du FOMC juge approprié pour chaque fin d'année et à long terme. Avis individuels, anonymes et non engageants : ni un plan, ni une prévision du résultat le plus probable.", guide: 'lire-le-dot-plot-sep' },
      { sigle: 'r*', nom: 'Taux neutre', def: "Taux directeur ni accommodant ni restrictif, vers lequel la politique convergerait à long terme sous une économie à l'équilibre. Approché par le point de long terme du dot plot ; comparé au taux courant, il mesure le caractère restrictif de la politique.", guide: 'lire-le-dot-plot-sep' },
      { sigle: 'Tendance centrale', nom: 'Central tendency', def: "Lecture intermédiaire du SEP entre la médiane et la fourchette : elle exclut les trois projections les plus hautes et les trois plus basses. Mesure la dispersion des avis au sein du FOMC, donc le degré d'accord du comité.", guide: 'lire-le-dot-plot-sep' },
      { sigle: 'FFR', nom: 'Federal Funds Rate', def: "Taux directeur de la Fed : fourchette cible pour le taux au jour le jour entre banques. Principal levier de la politique monétaire américaine." },
      { sigle: 'NFP', nom: 'Nonfarm Payrolls', def: "Emplois salariés non agricoles créés ou détruits sur le mois aux États-Unis, issus de l'enquête entreprises du BLS. La donnée macro la plus suivie des marchés, mais assortie d'un intervalle de confiance large (environ plus ou moins 122 000) et de fortes révisions.", guide: 'lire-le-rapport-emploi-nfp' },
      { sigle: 'U6', nom: 'Sous-emploi large', def: "Mesure large du chômage du BLS : ajoute au taux officiel (U3) les travailleurs découragés et ceux contraints au temps partiel. L'écart entre U6 et U3 dit la qualité du marché du travail, pas seulement son volume.", guide: 'lire-le-rapport-emploi-nfp' },
      { sigle: 'Taux de participation', nom: 'Labor force participation rate', def: "Part de la population active dans la population en âge de travailler. Un taux de chômage qui baisse parce que des personnes découragées quittent la population active n'est pas un signe de santé : le chômage se lit toujours avec la participation.", guide: 'lire-le-rapport-emploi-nfp' },
      { sigle: 'Modèle birth-death', nom: 'Birth-death model', def: "Ajustement statistique du BLS qui estime les emplois créés ou détruits par les entreprises naissant ou disparaissant sans figurer encore dans l'échantillon de l'enquête entreprises.", guide: 'lire-le-rapport-emploi-nfp' },
      { sigle: 'Révision de référence', nom: 'Benchmark revision', def: "Recalage annuel de l'enquête entreprises du BLS sur les registres quasi exhaustifs de l'assurance chômage. Mesure approchée de l'erreur totale : la révision préliminaire de mars 2025 a retranché 911 000 emplois.", guide: 'lire-le-rapport-emploi-nfp' },
      { sigle: 'JOLTS', nom: 'Job Openings and Labor Turnover Survey', def: "Enquête mensuelle du BLS sur les flux du marché du travail américain : postes vacants, embauches, démissions et licenciements. Complément du NFP, qui n'en donne que le solde net. Retarde d'un mois sur le rapport emploi.", guide: '/guides/lire-le-rapport-jolts/' },
      { sigle: 'Taux de démission', nom: 'Quits rate', def: "Démissions volontaires rapportées à l'emploi total, dans le JOLTS. Baromètre de la confiance des salariés : on ne quitte son poste que si l'on est confiant d'en retrouver un meilleur. Retombé à 2,0 % en 2026, sous sa norme d'avant-pandémie.", guide: '/guides/lire-le-rapport-jolts/' },
      { sigle: 'Ratio postes vacants / chômeurs', nom: 'Vacancy-to-unemployed ratio', def: "Nombre de postes vacants divisé par le nombre de chômeurs. Jauge de tension du marché du travail privilégiée par la Fed : près de 2,0 lors de la surchauffe de 2022, retombé autour de 0,95 en 2026, sous sa norme d'avant-pandémie (~1,2).", guide: '/guides/lire-le-rapport-jolts/' },
      { sigle: 'Courbe de Beveridge', nom: 'Beveridge curve', def: "Relation inverse entre le taux de postes vacants et le taux de chômage. Sa lecture dit si l'économie évacue une surchauffe sans casse (glissement le long de la courbe) ou approche du point où tout refroidissement supplémentaire détruit des emplois plutôt que des postes vacants.", guide: '/guides/lire-le-rapport-jolts/' },
      { sigle: 'QE', nom: 'Quantitative Easing', def: "Assouplissement quantitatif : achats massifs d'obligations par la banque centrale pour injecter des liquidités et peser sur les taux longs." },
      { sigle: 'H.4.1', nom: 'Factors Affecting Reserve Balances', def: "Relevé statistique hebdomadaire de la Réserve fédérale détaillant son bilan : titres détenus, prises en pension, prêts et lignes de swap à l'actif ; monnaie en circulation, compte du Trésor, prises en pension inverse et réserves bancaires au passif. Publié le jeudi à 16 h 30 heure de New York." },
      { sigle: 'Réserves bancaires', nom: 'Dépôts des institutions de dépôt à la Fed', def: "Dépôts que les banques détiennent à la Réserve fédérale, liquidité ultime de règlement. Dans le bilan de la Fed, elles sont un résidu : l'actif de la banque centrale moins la monnaie en circulation, le compte du Trésor et les prises en pension inverse." },
      { sigle: 'QT', nom: 'Quantitative Tightening', def: "Resserrement quantitatif, l'inverse du QE : la banque centrale laisse filer ou vend ses obligations, retirant des liquidités du système et tendant les taux longs." },
      { sigle: 'Liquidité nette', nom: 'Net liquidity', def: "Indicateur suivi par les marchés : bilan de la Réserve fédérale diminué du compte du Trésor (TGA) et des prises en pension inversées (RRP). Proxy de la liquidité disponible, utile en tendance mais trompeur aux retournements.", guide: '/guides/liquidite-tresor-dts-tga-rrp/' },
      { sigle: 'TGA', nom: 'Treasury General Account', def: "Compte courant de l'État fédéral américain à la Réserve fédérale. Quand il gonfle (émissions de dette), il draine les réserves bancaires ; quand il baisse (dépenses), il en réinjecte." },
      { sigle: 'RRP', nom: 'Reverse Repo (ON RRP)', def: "Facilité de prises en pension inversées au jour le jour de la Fed, où les fonds monétaires placent leur cash. Longtemps amortisseur de liquidité, tombée près de zéro en 2025." },
      { sigle: 'DTS', nom: 'Daily Treasury Statement', def: "Relevé quotidien du Trésor américain (Bureau of the Fiscal Service) détaillant encaissements, décaissements et solde de trésorerie. Source primaire pour suivre le TGA au jour le jour." },
      { sigle: 'Réhypothécation', nom: 'Réutilisation du collatéral', def: "Droit, pour celui qui reçoit un titre en garantie, de le redonner lui-même en garantie d'un autre engagement. Un même titre garantit alors plusieurs créances superposées, formant des chaînes de collatéral. Crée de la liquidité, mais aussi du levier caché et un risque de blocage en cascade." },
      { sigle: 'Vélocité du collatéral', nom: 'Velocity of collateral', def: "Rapport entre le volume total de collatéral reçu par les intermédiaires et le collatéral d'origine. Mesure de l'intensité de la réutilisation, sur le modèle de la vitesse de circulation de la monnaie. Estimée autour de 3 avant 2008, en baisse après Lehman, puis en rebond. Concept proposé par Manmohan Singh (FMI)." },
      { sigle: 'Repo', nom: 'Pension livrée (repurchase agreement)', def: "Vente d'un titre, le plus souvent une obligation du Trésor, assortie d'un rachat le lendemain à un prix légèrement supérieur. Prêt de cash garanti par le collatéral, brique de base du financement de marché au jour le jour." },
      { sigle: 'Haircut repo', nom: 'Décote de collatéral en repo', def: "Marge de sécurité appliquée à un actif donné en garantie dans une opération de repo. Un haircut faible augmente le levier possible ; un haircut qui monte force l'emprunteur à apporter du cash ou à réduire sa position." },
      { sigle: 'T-bill', nom: 'Treasury bill (bon du Trésor court)', def: "Titre de dette de l'État américain à échéance d'un an ou moins, émis à escompte et sans coupon. Réputé sans risque et très liquide, c'est l'actif de réserve central des stablecoins de paiement sous le GENIUS Act.", guide: '/guides/qui-applique-le-genius-act/' },
      { sigle: '2a-7', nom: 'Rule 2a-7', def: "Règle de la SEC qui encadre les fonds monétaires américains : qualité de crédit élevée, maturité moyenne pondérée plafonnée à 60 jours, coussins d'actifs liquides (au moins 25 % à un jour et 50 % à une semaine depuis 2023) et diversification. C'est elle qui permet à un fonds de viser une valeur liquidative stable à 1 dollar.", guide: '/guides/lire-les-fonds-monetaires/' },
      { sigle: 'Fonds prime', nom: 'Prime money market fund', def: "Fonds monétaire qui investit aussi en dette privée courte, billets de trésorerie et certificats de dépôt, en plus de la dette d'État. Plus rémunérateur qu'un fonds gouvernemental, mais plus risqué : ce sont les fonds prime qui ont rompu le pair en 2008 et subi les ruées de mars 2020.", guide: '/guides/lire-les-fonds-monetaires/' },
      { sigle: 'Billet de trésorerie', nom: 'Commercial paper', def: "Titre de dette à court terme émis par une entreprise ou une banque pour financer ses besoins courants. Actif de prédilection des fonds monétaires prime, mais dont le marché se gèle en cas de stress, comme après la faillite de Lehman en 2008.", guide: '/guides/lire-les-fonds-monetaires/' },
      { sigle: 'Break the buck', nom: 'Rompre le pair', def: "Situation où la valeur liquidative d'un fonds monétaire tombe sous 1 dollar, précisément sous 0,995, révélant une perte sur ses actifs. Rare mais redoutée, elle déclenche une ruée des porteurs, chacun voulant sortir au pair avant les autres. Le Reserve Primary Fund l'a fait en 2008, à 0,97 dollar.", guide: '/guides/lire-les-fonds-monetaires/' },
      { sigle: 'SRF', nom: 'Standing Repo Facility / Standing Repo Program', def: "Facilité permanente de la Fed permettant aux contreparties éligibles d'emprunter du cash contre Treasuries et MBS d'agence. Agit comme plafond sur les taux courts. Plafond agrégé supprimé et passage en allotissement intégral le 10 décembre 2025." },
      { sigle: 'IORB', nom: 'Interest On Reserve Balances', def: "Taux auquel la Fed rémunère les réserves que les banques détiennent chez elle. Outil central de pilotage des taux courts dans le régime de réserves abondantes : les banques n'ont guère intérêt à prêter en dessous." },
      { sigle: 'EFFR', nom: 'Effective Federal Funds Rate', def: "Taux effectif moyen des prêts en blanc au jour le jour entre banques américaines. Cible opérationnelle de la politique monétaire, encadrée par l'IORB, le RRP et le SRP." },
      { sigle: 'COFER', nom: 'Currency Composition of Official Foreign Exchange Reserves', def: "Base trimestrielle du FMI mesurant la composition en devises des réserves de change mondiales, hors or. Le dollar y pèse encore autour de 58 pour cent en 2025, contre près de 70 pour cent en 2000. À distinguer de la part de l'or, mesurée sur les réserves totales." },
      { sigle: 'Dédollarisation', nom: 'Diversification hors du dollar', def: "Réduction progressive de la part du dollar dans les réserves, les échanges et les financements, au profit d'autres devises et de l'or. Mouvement graduel et partiel, accéléré par la crainte des sanctions depuis 2022, plus qu'un abandon brutal du billet vert." },
      { sigle: 'TIC', nom: 'Treasury International Capital', def: "Système de relevés du Trésor américain mesurant les détentions et flux transfrontaliers de titres américains. Source de référence sur les détenteurs étrangers de Treasuries, mais sur une base de conservation qui attribue les titres au pays du dépositaire, pas au détenteur final.", guide: 'lire-les-donnees-tic' },
      { sigle: 'MFH', nom: 'Major Foreign Holders', def: "Table mensuelle du TIC classant les pays par stock de Treasuries détenus. Japon, Royaume-Uni et Chine en tête fin 2025, mais gonflée par les centres de garde (Belgique, Luxembourg, Caïmans, Irlande).", guide: 'lire-les-donnees-tic' },
      { sigle: 'Biais de conservation', nom: 'Custodial bias', def: "Limite majeure des données TIC : un titre est attribué au pays où il est conservé, non à celui de son propriétaire réel. Gonfle les places de garde et masque les vrais détenteurs ; l'enquête annuelle de référence le corrige en partie.", guide: 'lire-les-donnees-tic' },
      { sigle: 'Eurodollar', nom: 'Dollar offshore', def: "Dollar détenu ou prêté hors du système bancaire américain, sans lien avec la monnaie euro. Couche internationale du dollar, née dans les années 1950-1960, largement hors du champ direct de la Fed. Le crédit dollar aux non-banques hors US atteignait 14 300 milliards de dollars fin 2025." },
      { sigle: 'CIP', nom: 'Covered Interest Parity (parité couverte des taux)', def: "Relation théorique selon laquelle emprunter une devise directement ou la fabriquer en passant par une autre devise et un contrat à terme doit revenir au même. Considérée comme quasi inviolable avant 2008, elle ne tient plus depuis." },
      { sigle: 'Cross-currency basis', nom: 'Base cross-devises', def: "Écart résiduel quand la parité couverte des taux ne tient pas : prime payée pour obtenir des dollars en synthétique via un swap de change. Thermomètre du stress de financement en dollar, négatif et persistant depuis 2008, qui se creuse aux dates de bilan et en crise.", guide: '/guides/lire-le-dollar-dxy-cross-currency-basis/' },
      { sigle: 'DXY', nom: 'U.S. Dollar Index', def: "Indice du dollar contre un panier de six devises, dominé par l'euro (près de 58 %) et sans le yuan ni le peso. Panier inchangé depuis 1999, base 1973 = 100. Thermomètre commode mais biaisé : pour le dollar contre le monde réel, l'indice large pondéré par les échanges de la Fed est plus fidèle.", guide: '/guides/lire-le-dollar-dxy-cross-currency-basis/' },
      { sigle: 'CIP', nom: 'Parité couverte des taux (Covered Interest Parity)', def: "Relation d'arbitrage selon laquelle se procurer des dollars directement ou en synthétique via un swap de change devrait coûter exactement le différentiel de taux. Rompue depuis 2008 sous l'effet des limites à l'arbitrage et de la demande structurelle de dollars ; son écart résiduel est le cross-currency basis.", guide: '/guides/lire-le-dollar-dxy-cross-currency-basis/' },
      { sigle: 'Ligne de swap', nom: 'Central bank liquidity swap', def: "Accord par lequel la Fed prête des dollars à des banques centrales étrangères (BCE, BoJ, BoE…), qui les reprêtent à leurs banques. Filet de sécurité du financement dollar offshore, activé massivement en 2008 et en mars 2020. Visible à l'actif du bilan de la Fed.", guide: '/guides/lire-le-dollar-dxy-cross-currency-basis/' },
      { sigle: 'Swap de change', nom: 'FX swap', def: "Échange de devises au comptant assorti de l'opération inverse à terme. Économiquement proche d'un repo, avec une devise comme collatéral, mais enregistré hors bilan. Source d'une dette dollar « manquante » estimée par la BIS à des dizaines de milliers de milliards." },
      { sigle: 'SOFR', nom: 'Secured Overnight Financing Rate', def: "Taux de référence des financements garantis au jour le jour aux États-Unis, adossé aux pensions sur Treasuries. Thermomètre des tensions sur le marché du financement." },
      { sigle: 'PCE', nom: 'Personal Consumption Expenditures', def: "Indice des prix des dépenses de consommation calculé par le BEA, mesure d'inflation préférée de la Fed pour sa cible de 2 %. Plus large que le CPI et chaîné (formule de Fisher), il pèse la santé environ deux fois plus et le logement deux fois moins, et court en moyenne 0,4 point en dessous du CPI.", guide: '/guides/lire-le-pce-inflation-fed/' },
      { sigle: 'Core PCE', nom: 'PCE hors alimentation et énergie', def: "Indice PCE privé des postes alimentation et énergie, les plus volatils. Mesure de la tendance de fond que la Fed suit en pratique pour juger de la persistance de l'inflation, même si sa cible de 2 % porte sur le PCE total.", guide: '/guides/lire-le-pce-inflation-fed/' },
      { sigle: 'Trimmed mean PCE', nom: 'Moyenne tronquée du PCE', def: "Mesure robuste calculée par la Fed de Dallas, qui écarte chaque mois les composantes aux variations les plus extrêmes, en haut comme en bas de la distribution, plutôt que de retirer toujours l'alimentation et l'énergie. Capte mieux la tendance durable qu'un poste isolé pourrait fausser.", guide: '/guides/lire-le-pce-inflation-fed/' },
      { sigle: 'PCE market-based', nom: 'PCE fondé sur les prix de marché', def: "Sous-ensemble du PCE qui écarte les composantes aux prix imputés (services financiers estimés par les marges, loyers fictifs) pour ne garder que des prix réellement transactés. Lecture plus « propre » suivie par la Fed, moins sujette aux artefacts de mesure.", guide: '/guides/lire-le-pce-inflation-fed/' },
      { sigle: 'BTFP', nom: 'Bank Term Funding Program', def: "Facilité d'urgence créée par la Fed le 12 mars 2023 après la chute de SVB, prêtant à un an contre Treasuries et MBS d'agence valorisés au pair plutôt qu'à leur valeur de marché, donc en neutralisant les pertes latentes. Pic supérieur à 165 milliards de dollars ; fermée aux nouveaux prêts le 11 mars 2024, intégralement remboursée un an plus tard." },
      { sigle: 'Guichet de l\'escompte', nom: 'Discount window', def: "Facilité permanente par laquelle la Fed prête du cash aux banques contre un large éventail de collatéral. Outil de prêteur en dernier ressort, sous-utilisé à cause d'un stigmate persistant : y recourir est perçu comme un signe de faiblesse. Au cœur du débat 2026 sur la réforme de la liquidité." },
      { sigle: 'Pertes latentes', nom: 'Unrealized losses', def: "Moins-values sur titres détenus (Treasuries, MBS) non encore matérialisées par une vente. Quand les taux montent, la valeur de marché des obligations baisse : ces pertes restent au bilan tant que les titres ne sont pas cédés. Leur révélation forcée a précipité la chute de SVB en 2023." },
    ],
  },
  {
    titre: 'Crédit privé & marchés',
    accent: '#ff4d87',
    entries: [
      { sigle: 'Crédit privé', nom: 'Private credit', def: "Prêts accordés directement par des gérants non bancaires à des entreprises, sans cotation ni marché secondaire actif. Marché illiquide, peu réglementé et valorisé au modèle, de l'ordre de 1 300 milliards de dollars aux États-Unis.", guide: '/guides/analyser-credit-prive/' },
      { sigle: 'BDC', nom: 'Business Development Company', def: "Véhicule coté américain qui prête aux entreprises de taille moyenne. Pilier du crédit privé, souvent à effet de levier." },
      { sigle: 'Interval fund', nom: 'Fonds à intervalle', def: "Fonds semi-liquide qui n'autorise les rachats que par fenêtres périodiques et plafonnées. Tout en détenant des actifs illiquides, d'où un risque de gating en cas d'afflux de sorties." },
      { sigle: 'NAV', nom: 'Net Asset Value', def: "Valeur nette d'inventaire : valeur des actifs d'un fonds moins ses dettes. Pour les fonds privés, elle est estimée et non cotée, d'où des questions d'opacité." },
      { sigle: 'NAV loan', nom: 'Prêt sur valeur liquidative', def: "Emprunt contracté par un fonds contre la valeur liquidative de l'ensemble de son portefeuille, souvent pour financer investissements complémentaires ou distributions. Levier ajouté au niveau du fonds, par-dessus la dette des entreprises détenues, peu visible pour les investisseurs finaux. Quotité typique de 5 à 25 % de la NAV, collatéral croisé sur tout le portefeuille." },
      { sigle: 'Ligne de souscription', nom: 'Subscription line', def: "Crédit-relais consenti à un fonds en début de vie, garanti par les engagements non appelés de ses investisseurs (LP), pour financer les acquisitions avant les appels de capital. À l'inverse du NAV loan, qui arrive en fin de vie du fonds et se gage sur la valeur du portefeuille déjà investi." },
      { sigle: 'DPI', nom: 'Distributions to Paid-In', def: "Rapport entre le capital effectivement rendu aux investisseurs d'un fonds et le capital versé par eux. Mesure de performance « cash », insensible aux valorisations au modèle, devenue le critère dominant des investisseurs institutionnels pendant la sécheresse des sorties de 2023-2026. Un DPI gonflé par un emprunt n'est pas une performance, c'est une avance." },
      { sigle: 'Rated feeder note', nom: 'Note de fonds nourricier notée', def: "Titre de dette émis par un véhicule nourricier investi dans un fonds privé, assorti d'une notation, le plus souvent privée. Permet à un assureur de loger une exposition de type fonds en la traitant comme une obligation notée, avec une charge en capital réduite. Structure au cœur de l'examen engagé par la NAIC." },
      { sigle: 'Réassurance adossée à l’actif', nom: 'Asset-intensive reinsurance', def: "Cession de réserves d'assurance-vie ou de rentes à un réassureur, souvent affilié au même groupe et installé offshore, aux Bermudes en particulier. Le réassureur reprend les engagements et réinvestit les actifs, fréquemment en crédit privé et en produits structurés, sous un régime prudentiel plus souple que celui du régulateur d'origine." },
      { sigle: 'NAIC', nom: 'National Association of Insurance Commissioners', def: "Association des régulateurs d'assurance des États américains, qui harmonise les règles prudentielles du secteur. Son bureau des valeurs mobilières (SVO) fixe le traitement en capital des actifs détenus par les assureurs ; ses réformes de 2026 lui permettent d'outrepasser des notations jugées trop favorables." },
      { sigle: 'AUM', nom: 'Assets Under Management', def: "Encours sous gestion : montant total des actifs gérés par un fonds ou une société de gestion." },
      { sigle: 'PIK', nom: 'Payment In Kind', def: "Paiement en nature : intérêts d'une dette versés non en cash mais en dette supplémentaire. Signal de tension sur la trésorerie de l'emprunteur." },
      { sigle: 'LP', nom: 'Limited Partner', def: "Investisseur commanditaire d'un fonds (assureur, fonds de pension, family office) qui apporte le capital sans gérer." },
      { sigle: 'ETF', nom: 'Exchange-Traded Fund', def: "Fonds indiciel coté en bourse, qui réplique un indice ou un panier d'actifs et se négocie comme une action." },
      { sigle: 'PER', nom: 'Price-Earnings Ratio', def: "Rapport entre le cours d'une action ou d'un indice et son bénéfice par action. Mesure combien les investisseurs paient pour un euro de bénéfice courant. Élevé, il traduit soit de fortes attentes de croissance, soit une survalorisation." },
      { sigle: 'CAPE', nom: 'Cyclically Adjusted Price-to-Earnings', def: "Ratio de valorisation popularisé par Robert Shiller, qui rapporte le prix à la moyenne des bénéfices sur dix ans corrigés de l'inflation, pour lisser le cycle. Utile pour comparer les valorisations dans le temps : un CAPE très élevé annonce un rendement futur médiocre à long terme, sans donner de calendrier. Sommets historiques : 32,6 en 1929, 44,2 en 2000." },
      { sigle: 'Yen carry', nom: 'Yen carry trade', def: "Stratégie qui consiste à emprunter en yen, devise historiquement peu rémunérée, pour acheter des actifs ou devises offrant un rendement supérieur. Fonctionne tant que le yen reste faible et que la volatilité demeure contenue.", guide: '/guides/lire-le-carry-trade/' },
      { sigle: 'Carry trade', nom: 'Portage', def: "Stratégie qui emprunte dans une devise à bas rendement pour placer dans un actif mieux rémunéré et empocher l'écart. Elle revient à vendre implicitement de la volatilité : un revenu régulier tant que le calme règne, une perte brutale quand le change se retourne. Le yen carry en est le cas le plus connu.", guide: '/guides/lire-le-carry-trade/' },
      { sigle: 'Devise de financement', nom: 'Funding currency', def: "Monnaie empruntée pour financer un portage, choisie pour son faible taux d'intérêt et sa stabilité : historiquement le yen et le franc suisse, le dollar durant les années de taux zéro. Sa remontée soudaine, en taux ou en change, est le principal déclencheur d'un débouclage.", guide: '/guides/lire-le-carry-trade/' },
      { sigle: 'LME metals', nom: 'London Metal Exchange', def: "Bourse londonienne des métaux industriels. Son contrat cuivre sert de référence mondiale pour le prix physique et financier du cuivre." },
      { sigle: 'ICSG', nom: 'International Copper Study Group', def: "Organisation intergouvernementale qui publie les statistiques mondiales de production, d'usage, de stocks et de prix du cuivre." },
      { sigle: 'SX-EW', nom: 'Solvent Extraction Electrowinning', def: "Procédé hydrométallurgique d'extraction du cuivre : le minerai est lixivié, souvent avec de l'acide sulfurique, puis le métal est récupéré par électrolyse." },
      { sigle: 'LBMA', nom: 'London Bullion Market Association', def: "Association qui coordonne le marché de gré à gré de l'or et de l'argent à Londres, cœur du marché physique mondial (livraison « loco London »). Le LBMA Gold Price, fixé deux fois par jour par enchère électronique administrée par ICE, est la référence mondiale du cours de l'or.", guide: '/guides/lire-le-marche-de-l-or/' },
      { sigle: 'Comex', nom: 'Commodity Exchange (New York)', def: "Bourse à terme new-yorkaise où se traitent les contrats sur l'or et les métaux. N'ancre pas le physique mais l'amplifie : ses positions à effet de levier dépassent de loin l'or livrable, et son prix transmet les anticipations.", guide: '/guides/lire-le-marche-de-l-or/' },
      { sigle: 'London Metal Exchange', nom: 'LME (métaux)', def: "Bourse des métaux de base de Londres, référence mondiale du prix du cuivre, de l'aluminium et des autres métaux industriels. Elle cote un prix comptant et un prix à trois mois, et gère un réseau d'entrepôts dont les stocks servent de baromètre de tension physique. À ne pas confondre avec l'autre sigle LME, la gestion de passif.", guide: '/guides/lire-le-marche-du-cuivre/' },
      { sigle: 'Dr Copper', nom: 'Docteur Cuivre', def: "Surnom du cuivre, le métal réputé doté d'un doctorat en économie, car son prix suit de près la santé de l'industrie mondiale. Présent partout, du bâtiment à l'électronique, il anticipe souvent les cycles. Le signal est aujourd'hui brouillé par la demande d'électrification et les flux liés aux tarifs douaniers.", guide: '/guides/lire-le-marche-du-cuivre/' },
      { sigle: 'TC/RC', nom: 'Treatment and refining charges', def: "Frais que les fonderies facturent aux mines pour transformer le concentré de cuivre en métal raffiné. Quand ils s'effondrent, voire deviennent négatifs comme en 2025-2026, c'est le signe d'une pénurie de concentré et d'une surcapacité de fonderies, un indicateur avancé de tension sur l'offre.", guide: '/guides/lire-le-marche-du-cuivre/' },
      { sigle: 'Section 232', nom: 'Section 232 (Trade Expansion Act)', def: "Disposition du droit commercial américain autorisant des tarifs sur des importations jugées menaçantes pour la sécurité nationale. Invoquée pour l'acier, l'aluminium, puis le cuivre : le tarif cuivre a écarté le prix new-yorkais (COMEX) du prix mondial (LME) en 2025-2026.", guide: '/guides/lire-le-marche-du-cuivre/' },
      { sigle: 'EFP', nom: 'Exchange for Physical', def: "Opération permettant de convertir une position à terme sur le Comex en or physique « loco London », et inversement. L'écart de prix EFP reste normalement étroit ; il s'élargit brutalement en cas de forte demande de métal réel, signalant une dislocation entre papier et physique.", guide: '/guides/lire-le-marche-de-l-or/' },
      { sigle: "Taux de prêt de l'or", nom: 'Gold lease rate', def: "Rendement implicite tiré du prêt d'or physique. Quand le métal se raréfie, ce taux grimpe, tirant les cours à terme sous le comptant et asséchant la liquidité disponible à la livraison.", guide: '/guides/lire-le-marche-de-l-or/' },
      { sigle: 'Financement circulaire', nom: 'Circular financing', def: "Arrangement où un petit groupe d'acteurs interconnectés s'investissent et se facturent mutuellement, si bien que le capital injecté revient en chiffre d'affaires. Peut donner l'apparence d'une demande organique. Au cœur du débat sur les valorisations de l'IA en 2025-2026." },
      { sigle: 'Vendor financing', nom: 'Financement fournisseur', def: "Pratique par laquelle un fournisseur finance ses propres clients (prêts, prises de participation, garanties d'achat) pour soutenir la demande de ses produits. Légitime en soi, elle peut masquer la fragilité de la demande réelle, comme lors de la bulle télécoms des années 1990." },
      { sigle: 'IPO', nom: 'Initial Public Offering', def: "Introduction en bourse : première mise sur le marché des actions d'une société auprès du public." },
      { sigle: 'NDFI', nom: 'Non-Depository Financial Institution', def: "Institution financière non bancaire (fonds de crédit privé, capital-investissement, assureurs), sans dépôts. Au cœur du « shadow banking » car peu régulée comme les banques. Les grandes banques n'y sont souvent pas exposées en direct, mais par les crédits qu'elles leur consentent, ce qui reconnecte le système bancaire au crédit de l'ombre. Poste de risque en forte croissance dans les bilans." },
      { sigle: 'NBFI', nom: 'Non-Bank Financial Intermediation', def: "Intermédiation financière non bancaire : l'ensemble du financement hors banques (fonds, assureurs, véhicules de titrisation, crédit privé). Suivie par le Conseil de stabilité financière, elle représente désormais plus de la moitié des actifs financiers mondiaux, environ 250 000 milliards de dollars. Nouveau nom du « shadow banking »." },
      { sigle: 'Arbitrage réglementaire', nom: 'Regulatory arbitrage', def: "Déplacement d'une activité vers le compartiment le moins régulé du système financier, pour échapper aux contraintes de fonds propres ou de transparence. Moteur de la croissance du non-bancaire depuis le durcissement des règles bancaires après 2008 : le risque ne disparaît pas, il change d'adresse." },
      { sigle: 'AIMA', nom: 'Alternative Investment Management Association', def: "Association professionnelle mondiale des gérants d'actifs alternatifs (hedge funds, crédit privé)." },
      { sigle: 'Hyperscaler', nom: 'Géant du cloud', def: "Très grand opérateur d'infrastructure informatique en nuage, comme Microsoft, Google, Amazon ou Oracle, qui construit et exploite des centres de données à grande échelle. Au cœur du boom d'investissement dans l'IA." },
      { sigle: 'Capex', nom: "Dépenses d'investissement", def: "Capital expenditures : dépenses engagées pour acquérir ou construire des actifs durables, centres de données, serveurs, équipements. Le boom de l'IA se mesure d'abord à l'explosion de ces dépenses." },
      { sigle: 'Semi-conducteur', nom: 'Semiconductor', def: "Composant électronique gravé dans un matériau conducteur contrôlé, le plus souvent du silicium. Il sert de brique de base aux processeurs, mémoires, capteurs, équipements industriels, véhicules, télécoms et systèmes de défense." },
      { sigle: 'Fonderie', nom: 'Semiconductor foundry', def: "Usine ou groupe industriel qui fabrique des puces conçues par d'autres. Le modèle sépare la conception fabless de la production, mais concentre le risque opérationnel sur quelques sites et fournisseurs critiques." },
      { sigle: 'EUV', nom: 'Extreme Ultraviolet Lithography', def: "Lithographie à ultraviolet extrême, technologie de gravure nécessaire aux noeuds logiques les plus avancés. C'est l'un des principaux goulots de la chaîne semi-conducteurs, car les machines sont très coûteuses, complexes et soumises aux contrôles export." },
      { sigle: 'HBM', nom: 'High Bandwidth Memory', def: "Mémoire empilée à très haut débit, utilisée avec les accélérateurs d'IA. Elle déplace le goulot de la puce seule vers la mémoire, l'interconnexion et le packaging avancé." },
      { sigle: 'EDA', nom: 'Electronic Design Automation', def: "Logiciels de conception assistée des circuits intégrés. Ils permettent de dessiner, simuler, vérifier et préparer une puce avant fabrication, et constituent une couche stratégique souvent moins visible que les usines." },
      { sigle: 'CDS', nom: 'Credit default swap', def: "Contrat d'assurance contre le défaut d'un émetteur de dette. Sa prime, exprimée en points de base, mesure le risque de crédit perçu : elle monte quand le marché juge le défaut plus probable." },
      { sigle: 'Spread de crédit', nom: 'Credit spread', def: "Écart de rendement entre une obligation d'entreprise et une obligation d'État de même maturité. Prix du risque de crédit : il s'écarte quand le marché exige davantage pour prêter à un émetteur privé, se resserre quand l'appétit pour le risque revient.", guide: '/guides/lire-les-spreads-de-credit/' },
      { sigle: 'OAS', nom: 'Option-Adjusted Spread', def: "Écart de rendement d'une obligation par rapport à la courbe des Treasuries, corrigé de la valeur des options incorporées au titre (clause de remboursement anticipé). Mesure de référence du spread de crédit, comparable d'un titre à l'autre. Les indices ICE BofA sont la source la plus suivie.", guide: '/guides/lire-les-spreads-de-credit/' },
      { sigle: 'Investment grade', nom: 'Catégorie investissement', def: "Émetteurs les mieux notés, de AAA à BBB-. Dette jugée de qualité, à faible probabilité de défaut, éligible à de nombreux portefeuilles réglementés. En dessous commence le high yield." },
      { sigle: 'High yield', nom: 'Haut rendement', def: "Dette d'émetteurs notés sous BBB- (BB, B, CCC et moins), dite à haut rendement ou spéculative. Rémunère un risque de défaut plus élevé ; son spread est l'un des baromètres les plus suivis du stress de crédit." },
      { sigle: 'CDX', nom: 'Indice de CDS', def: "Indice regroupant un panier de credit default swaps (CDX.NA.IG pour l'investment grade, CDX.NA.HY pour le high yield). Instrument synthétique et liquide, il se négocie en continu et bouge souvent plus vite que le marché comptant des obligations." },
      { sigle: 'NRSRO', nom: 'Nationally Recognized Statistical Rating Organization', def: "Agence de notation agréée par la SEC pour que ses notes servent à des fins réglementaires. S&P, Moody's et Fitch, les trois principales, concentrent environ 95 % du marché mondial. Leur modèle dominant, l'émetteur-payeur, où l'entité notée paie sa propre note, porte un conflit d'intérêts structurel.", guide: '/guides/lire-une-notation-de-credit/' },
      { sigle: 'Matrice de transition', nom: 'Rating transition matrix', def: "Tableau qui donne, pour chaque note de départ, la probabilité de migrer vers une autre note (hausse, baisse ou défaut) sur un horizon donné, en général un an. Outil central de la gestion du risque de crédit, calibré sur l'historique des notations.", guide: '/guides/lire-une-notation-de-credit/' },
      { sigle: 'Ratio de détresse', nom: 'Distress ratio', def: "Part des obligations à haut rendement dont le spread dépasse 1 000 points de base. Mesure la taille du segment déjà en difficulté ; sa montée précède généralement les vagues de défaut." },
      { sigle: 'NBFI', nom: 'Non-Bank Financial Intermediation (intermédiation financière non bancaire)', def: "Ensemble des acteurs qui font du crédit ou de la transformation d'épargne hors du système bancaire : fonds monétaires, hedge funds, fonds d'investissement, assureurs, crédit privé, véhicules de titrisation. Terme préféré par les régulateurs à « shadow banking ». Pesait 256 800 milliards de dollars fin 2024, soit 51 pour cent des actifs financiers mondiaux." },
      { sigle: 'FSB', nom: 'Financial Stability Board', def: "Conseil de stabilité financière, qui coordonne au niveau international la surveillance des risques systémiques." },
      { sigle: 'PCDR', nom: 'Private Credit Default Rate', def: "Indice de Fitch mesurant le taux de défaut sur environ 1 200 emprunteurs du middle market dans le crédit privé. Mesure élargie du défaut, plus complète que le seul défaut de paiement." },
      { sigle: 'PMR', nom: 'Privately Monitored Rating', def: "Composante de l'univers Fitch portant sur les plus gros emprunteurs sous LBO notés en privé. Son taux de défaut est structurellement plus élevé que l'indice large PCDR." },
      { sigle: 'LME', nom: 'Liability Management Exercise', def: "Gestion de passif hors tribunal (échange de dette, extension de maturité, rachat sous le pair) qui permet d'éviter ou de repousser un défaut formel. Devenue le mode dominant de traitement de la détresse : en 2025-2026, ces restructurations forment l'essentiel de l'activité de défaut, masquant un stress que le taux de défaut classique sous-estime.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'LBO', nom: 'Leveraged Buyout', def: "Rachat d'entreprise financé majoritairement par de la dette, remboursée par les flux de trésorerie de la cible." },
      { sigle: 'CLO', nom: 'Collateralized Loan Obligation', def: "Véhicule de titrisation qui regroupe des centaines de prêts à effet de levier et émet des tranches de risque échelonné, de la plus sûre (AAA) à la plus risquée (equity). Premier acheteur du marché des prêts à effet de levier, activement géré. À ne pas confondre avec le CDO adossé aux crédits subprime de 2008.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'Prêt à effet de levier', nom: 'Leveraged loan', def: "Prêt bancaire syndiqué consenti à une entreprise déjà endettée, sous la catégorie investissement, à taux variable indexé sur le SOFR. Sert à financer rachats (LBO), acquisitions et refinancements. Senior et garanti, mais de plus en plus dépourvu de clauses de protection (cov-lite).", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'Cov-lite', nom: 'Covenant-lite', def: "Prêt émis avec peu ou pas de clauses de sauvegarde (covenants) obligeant l'emprunteur à respecter des ratios financiers. Devenu la norme du marché des prêts à effet de levier, il retarde le constat de défaut mais réduit le recouvrement des créanciers.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'Tranche', nom: 'Tranche de titrisation', def: "Part d'un véhicule de titrisation portant un niveau de risque défini. Les tranches senior (AAA) sont payées en premier et absorbent les pertes en dernier ; la tranche equity, en bas, encaisse les premières pertes contre le rendement le plus élevé. La hiérarchie s'appelle la cascade.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'Titrisation', nom: 'Securitization', def: "Technique consistant à regrouper des créances (prêts, obligations) dans un véhicule dédié qui émet des titres adossés à ces actifs, répartis en tranches de risque. Au cœur des CLO comme des CDO subprime, pour le meilleur et pour le pire.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'CRE', nom: 'Commercial Real Estate', def: "Immobilier commercial : bureaux, commerces, entrepôts, logements collectifs de rapport, hôtels. Financé par de la dette à échéance courte qu'il faut refinancer régulièrement. Aux États-Unis, un poste de risque concentré dans les banques régionales et frappé par le télétravail sur le segment des bureaux." },
      { sigle: 'CMBS', nom: 'Commercial Mortgage-Backed Securities', def: "Titres adossés à un panier de prêts immobiliers commerciaux, cousins des RMBS résidentiels. Leur taux de défaut, en particulier sur les bureaux, et leur passage en « special servicing » (gestion des créances en difficulté) sont des baromètres suivis du stress de l'immobilier commercial." },
      { sigle: 'Extend and pretend', nom: 'Extension et déni', def: "Pratique consistant, pour un prêteur, à prolonger l'échéance d'un prêt en difficulté plutôt qu'à constater la perte. Répandue dans l'immobilier commercial et le crédit à effet de levier, elle gagne du temps et lisse les pertes, mais masque le stress réel et retarde le nettoyage.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'Mur de maturités', nom: 'Maturity wall', def: "Concentration, sur une période courte, d'un grand volume de dette arrivant à échéance et devant être refinancée. Dangereux quand ce refinancement se fait à des taux bien plus élevés qu'à l'origine, comme pour l'immobilier commercial américain en 2026-2027." },
      { sigle: 'CDO', nom: 'Collateralized Debt Obligation', def: "Ancêtre et cousin du CLO, mais adossé à des crédits hypothécaires, souvent subprime, dans les années 2000. Son effondrement en 2008, aggravé par des tranches re-titrisées et corrélées, en a fait un symbole de la crise. Le CLO, adossé à des prêts d'entreprise diversifiés, a mieux résisté.", guide: '/guides/lire-les-clo-et-prets-a-effet-de-levier/' },
      { sigle: 'SPV', nom: 'Special Purpose Vehicle', def: "Véhicule ad hoc créé pour isoler un actif ou un financement. Sert par exemple à acheter du matériel puis à le louer, en gardant la dette hors du bilan de l'utilisateur." },
      { sigle: 'VRG', nom: 'Valeur résiduelle garantie', def: "Engagement par lequel le locataire d'un actif (data center, GPU, avion) garantit au prêteur une valeur plancher de cet actif à la fin du bail : si la revente rapporte moins, il comble l'écart. La garantie rend le montage finançable et le sort du bilan du locataire, mais transfère le risque de dépréciation au garant, sans le supprimer. Pièce centrale des financements d'infrastructure IA adossés au matériel." },
      { sigle: 'Neocloud', nom: 'Neocloud (GPU cloud)', def: "Opérateur de cloud spécialisé dans la location de puissance de calcul GPU pour l'IA, comme CoreWeave. Finance l'achat de puces Nvidia par de la dette adossée au matériel et à des contrats clients, en pariant sur une valeur résiduelle et un taux d'utilisation élevés." },
      { sigle: 'EBITDA', nom: 'Earnings Before Interest, Taxes, Depreciation and Amortization', def: "Résultat avant intérêts, impôts, dépréciations et amortissements. Proxy de la génération de cash opérationnel, sur lequel on dimensionne la dette." },
    ],
  },
  {
    titre: 'Crypto & stablecoins',
    accent: 'var(--color-amber)',
    entries: [
      { sigle: 'BTC', nom: 'Bitcoin', def: "Première cryptomonnaie, décentralisée, à offre plafonnée à 21 millions d'unités. Distincte de l'écosystème DeFi par sa conception." },
      { sigle: 'ETH', nom: 'Ether', def: "Cryptomonnaie native de la blockchain Ethereum, qui sert à payer les transactions et fait tourner les contrats intelligents." },
      { sigle: 'On-chain', nom: 'Donnée on-chain', def: "Données inscrites publiquement sur une blockchain : transactions, soldes, dates. Registre permanent et en temps réel, lisible par tous, mais qui exige des heuristiques d'étiquetage pour passer de l'adresse à l'acteur.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'UTXO', nom: 'Unspent Transaction Output', def: "Sortie de transaction non dépensée : modèle comptable de Bitcoin où un solde est la somme de fragments reçus et non encore redépensés. Permet de dater chaque pièce à son dernier mouvement. Ethereum utilise un modèle de comptes.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'Adresses actives', nom: 'Active addresses', def: "Nombre d'adresses ayant émis ou reçu une transaction sur une période. Approche l'usage d'un réseau, sans être un compteur d'utilisateurs : une personne peut détenir des centaines d'adresses, une plateforme en regroupe des millions.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'Capitalisation réalisée', nom: 'Realized cap', def: "Valorisation de chaque pièce au prix de son dernier mouvement on-chain, et non au prix du jour. Divisée par l'offre, elle donne le prix réalisé, lu comme le coût de revient moyen des détenteurs.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'MVRV', nom: 'Market Value to Realized Value', def: "Rapport entre la capitalisation de marché et la capitalisation réalisée. Mesure le profit ou la perte latente moyenne des détenteurs : au-dessus de 3,5, euphorie historique ; sous 1, capitulation. Introduit par Mahmudov et Puell en 2018.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'SOPR', nom: 'Spent Output Profit Ratio', def: "Indique si les pièces déplacées un jour donné le sont en gain (au-dessus de 1) ou en perte (en dessous). La version ajustée ignore les pièces dépensées en moins d'une heure. Thermomètre du sentiment des vendeurs.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'NVT', nom: 'Network Value to Transactions', def: "Capitalisation rapportée au volume de transfert on-chain en dollars, à la manière d'un multiple de valorisation pour une blockchain. À comparer à l'historique du même réseau, jamais d'un actif à l'autre.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'Exchange reserve', nom: "Réserve d'exchange", def: "Stock de cryptoactifs détenu sur les adresses des plateformes d'échange. Sa baisse traduit historiquement une mise en auto-conservation, signal devenu ambigu depuis que la conservation d'ETF est classée dans les mêmes adresses.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'Offre illiquide', nom: 'Illiquid supply', def: "Part de l'offre détenue dans des portefeuilles qui dépensent peu ou pas, proche de 70 % du bitcoin en circulation début 2026. Indicateur de conviction de détention longue, à croiser avec les réserves d'exchange.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'DAT', nom: 'Digital Asset Treasury', def: "Société à trésorerie numérique, dont le bilan est majoritairement constitué de cryptoactifs financés par émission de titres. Strategy (ex-MicroStrategy) en est l'archétype ; le modèle dépend de la prime sur l'actif net." },
      { sigle: 'mNAV', nom: 'Market net asset value', def: "Rapport entre la capitalisation d'une société à trésorerie numérique et la valeur de marché de ses cryptoactifs. Au-dessus de 1, émettre des actions est relutif ; sous 1, le financement par actions devient dilutif et le modèle se grippe." },
      { sigle: 'BTC Yield', nom: 'Rendement en bitcoin', def: "Métrique propre à Strategy : variation du nombre de bitcoins par action diluée sur une période. Mesure la relution de la stratégie d'accumulation, sans être un rendement au sens classique." },
      { sigle: 'Ethereum', nom: 'Couche de règlement programmable', def: "Blockchain publique programmable qui exécute des contrats intelligents et sert de couche de règlement pour ETH, stablecoins, rollups, DeFi et actifs tokenisés.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'EVM', nom: 'Ethereum Virtual Machine', def: "Machine virtuelle d'Ethereum qui exécute le code des smart contracts. Son importance vient de son effet standard : outils, wallets, audits et applications peuvent se réutiliser sur de nombreux réseaux compatibles.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Smart contract', nom: 'Contrat intelligent', def: "Programme déployé sur une blockchain, capable de détenir des actifs et d'exécuter des règles de transfert ou de calcul. Utile pour automatiser le règlement, mais exposé au risque de bug, d'oracle et de gouvernance.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Rollup', nom: 'Couche 2 ancrée sur Ethereum', def: "Réseau qui exécute des transactions hors de la L1 puis publie vers Ethereum les données, preuves ou engagements nécessaires à la vérification. Réduit les coûts mais ajoute des risques de séquenceur, de preuve et de mise à jour.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'L2', nom: 'Layer 2', def: "Couche d'exécution construite au-dessus d'Ethereum. Elle sert à augmenter le débit et réduire les frais, pendant que la L1 conserve le rôle de règlement et de disponibilité de données.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Blob', nom: 'Donnée temporaire pour rollups', def: "Paquet de données introduit par EIP-4844. Les blobs rendent les données des rollups moins coûteuses que le calldata classique, car elles servent à la disponibilité sans être conservées indéfiniment par l'exécution.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'EIP-4844', nom: 'Proto-danksharding', def: "Amélioration activée avec Dencun qui ajoute les transactions à blobs. Elle donne aux rollups un couloir de données moins cher et prépare l'architecture de sharding de données.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Data availability', nom: 'Disponibilité de données', def: "Garantie que les données nécessaires pour vérifier ou reconstruire l'état d'un rollup sont accessibles. Sans disponibilité de données, une preuve ou un engagement peut devenir impossible à contester utilement.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Séquenceur', nom: 'Rollup sequencer', def: "Acteur qui ordonne les transactions d'un rollup avant publication vers Ethereum. Un séquenceur centralisé améliore souvent l'expérience utilisateur, mais crée un point de contrôle et de censure potentiel.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Account abstraction', nom: 'Comptes programmables', def: "Famille de mécanismes qui donnent aux wallets des règles de validation plus souples : récupération, permissions, paiement du gas par un tiers, batch de transactions et politiques de signature.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'PBS', nom: 'Proposer-builder separation', def: "Séparation entre l'acteur qui propose un bloc et celui qui le construit. Vise à gérer la spécialisation du marché des blocs et à limiter certains risques de MEV et de censure.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'MEV', nom: 'Maximal Extractable Value', def: "Valeur extractible par le choix, l'ordre ou l'inclusion des transactions dans un bloc. Transforme la construction des blocs en microstructure de marché et peut créer front-running, sandwich attacks ou priorités opaques.", guide: '/posts/ethereum-tradfi-infrastructure-finance/' },
      { sigle: 'Stablecoin', nom: 'Jeton stable', def: "Jeton numérique adossé un pour un à une monnaie (le dollar dans près de 99 % des cas) et remboursable au pair. Sa valeur ne tient qu'à la qualité et à la liquidité de ses réserves.", guide: '/guides/stablecoins-genius-act/' },
      { sigle: 'WLFI', nom: 'World Liberty Financial', def: "Plateforme crypto liée à la famille Trump, émettrice du stablecoin USD1 et du jeton de gouvernance WLFI. Une entité du président en détient une large part et capte une fraction majeure du produit des ventes de jetons." },
      { sigle: 'Memecoin', nom: 'Jeton mème', def: "Crypto-actif sans utilité sous-jacente claire, dont la valeur repose sur la notoriété, le sentiment social ou une figure publique. Le jeton à l'effigie de Donald Trump en est l'exemple le plus médiatisé." },
      { sigle: 'USDT', nom: 'Tether', def: "Plus grand stablecoin en circulation, censé valoir un dollar. Émis par Tether, souvent au cœur des débats sur la transparence des réserves." },
      { sigle: 'USDC', nom: 'USD Coin', def: "Stablecoin adossé au dollar émis par Circle, présenté comme plus transparent sur ses réserves que l'USDT." },
      { sigle: 'DePIN', nom: 'Decentralized Physical Infrastructure Network', def: "Réseau qui rémunère en jetons des particuliers mettant à disposition une infrastructure physique, GPU, stockage, capteurs, sans opérateur central. Appliqué à l'IA, il agrège des cartes graphiques inutilisées pour louer du calcul moins cher que les hyperscalers, au prix d'une fiabilité et d'une offre dépendantes du cours du jeton." },
      { sigle: 'zkML', nom: 'Zero-Knowledge Machine Learning', def: "Usage des preuves à divulgation nulle de connaissance pour certifier qu'un modèle d'IA a bien produit un résultat donné, sans révéler ni le modèle ni les données. Piste pour vérifier une IA « boîte noire », encore bridée par un coût de preuve élevé." },
      { sigle: 'Agent autonome', nom: 'AI agent', def: "Programme d'intelligence artificielle capable d'agir de lui-même, y compris de payer et de transacter au nom d'un utilisateur. Son essor pose la question des rails de paiement adaptés aux micropaiements et de la responsabilité juridique de ses actes." },
      { sigle: 'x402', nom: 'Protocole de paiement x402', def: "Protocole ouvert lancé par Coinbase et Cloudflare fin 2025, qui ressuscite le code HTTP 402 « Payment Required » dormant depuis 1997. Un agent qui atteint une ressource payante reçoit un code 402, règle en stablecoin via un contrat sur la chaîne Base, puis rejoue sa requête avec un reçu on-chain. Rend possibles des micropaiements de machine à machine, sans compte ni intervention humaine." },
      { sigle: 'Commerce agentique', nom: 'Agentic commerce', def: "Commerce où des agents d'IA achètent et paient de façon autonome au nom d'un utilisateur, en très petits montants et sans validation humaine à chaque transaction. Suppose une pile de standards distinguant l'identité de l'agent, l'autorisation de dépense et l'exécution du paiement." },
      { sigle: 'Preuve d\'humanité', nom: 'Proof of personhood', def: "Mécanisme visant à prouver qu'un acteur en ligne est un humain réel et unique, ni un bot ni une multitude de faux comptes. Enjeu croissant face aux agents IA et aux deepfakes ; les approches crypto combinent biométrie (World ID) et divulgation sélective par preuve à divulgation nulle." },
      { sigle: 'RLUSD', nom: 'Ripple USD', def: "Stablecoin dollar émis par Ripple, plus récent, adossé à des liquidités et bons du Trésor." },
      { sigle: 'TVL', nom: 'Total Value Locked', def: "Valeur totale verrouillée dans un protocole DeFi : somme des actifs déposés dans ses contrats, valorisée en dollars (référence : DefiLlama). Mesure d'adoption, mais sensible au prix des jetons et au double comptage.", guide: '/guides/lire-la-donnee-on-chain/' },
      { sigle: 'DAO', nom: 'Decentralized Autonomous Organization', def: "Organisation autonome décentralisée : structure gouvernée par des votes on-chain plutôt que par une hiérarchie classique." },
      { sigle: 'RWA', nom: 'Real World Assets', def: "Actifs du monde réel (obligations, immobilier) tokenisés sur une blockchain pour être échangés on-chain." },
      { sigle: 'Immobilier tokenisé', nom: 'Tokenized real estate', def: "Fractionnement d'un bien immobilier en jetons échangeables on-chain, chaque bien logé dans une société dédiée (souvent une LLC) dont les parts sont tokenisées, le loyer étant reversé en stablecoin. Sa faille propre : le jeton ne vaut que si le titre de propriété off-chain (acte, registre foncier, fiscalité) suit réellement, ce que la liquidation de RealT en 2026 a mis en lumière. Reste marginal (moins de 100 M$ on-chain) face aux créances financières tokenisées." },
      { sigle: 'DeFi', nom: 'Decentralized Finance', def: "Finance décentralisée : services financiers (prêt, échange) opérés par des contrats intelligents sans intermédiaire bancaire." },
      { sigle: 'DEX', nom: 'Bourse décentralisée', def: "Plateforme d'échange de cryptoactifs fonctionnant sur une blockchain, sans intermédiaire central détenant les fonds. Hyperliquid en est un cas particulier, avec un carnet d'ordres entièrement on-chain." },
      { sigle: 'Perp', nom: 'Contrat perpétuel', def: "Contrat à terme crypto sans date d'échéance, maintenu proche du prix au comptant par un taux de financement périodique. Produit phare des bourses de dérivés crypto comme Hyperliquid." },
      { sigle: 'Buyback de token', nom: 'Rachat de token', def: "Rachat par un protocole de son propre jeton sur le marché, financé par ses revenus, à la manière d'une entreprise rachetant ses actions. Chez Hyperliquid, près de 97 % des frais alimentent ces rachats." },
      { sigle: 'MiCA', nom: 'Markets in Crypto-Assets', def: "Règlement (UE) 2023/1114, cadre unifié de l'Union pour les crypto-actifs non couverts par la réglementation financière existante. Un agrément national ouvre un passeport vers les 27 États membres.", guide: '/guides/mica-sigle-par-sigle/' },
      { sigle: 'CASP', nom: 'Crypto-Asset Service Provider', def: "Prestataire de services sur crypto-actifs (échange, conservation, exécution) soumis à agrément sous MiCA." },
      { sigle: 'ART', nom: 'Asset-Referenced Token', def: "Stablecoin adossé à un panier d'actifs (devises, matières premières, crypto), par opposition à l'EMT adossé à une seule monnaie." },
      { sigle: 'EMT', nom: 'E-Money Token', def: "Stablecoin indexé 1:1 sur une seule monnaie fiduciaire (EURC, USDC), régime le plus strict sous MiCA." },
      { sigle: 'ESMA', nom: 'European Securities and Markets Authority', def: "Autorité européenne des marchés financiers : coordonne l'application harmonisée de MiCA et tient le registre des agréments." },
      { sigle: 'EBA', nom: 'European Banking Authority', def: "Autorité bancaire européenne : supervise directement les émetteurs de stablecoins jugés significatifs sous MiCA et fixe les normes prudentielles de réserves et de fonds propres." },
      { sigle: 'NCA', nom: 'National Competent Authority', def: "Autorité nationale compétente (AMF en France, HCMC en Grèce) qui délivre l'agrément MiCA ouvrant le passeport européen." },
      { sigle: 'MCP', nom: 'Model Context Protocol', def: "Standard ouvert d'Anthropic (novembre 2024, JSON-RPC 2.0) reliant une IA à des outils et données externes. Confié à la Linux Foundation (AAIF) en décembre 2025. Adopté par OpenAI, Google et Microsoft." },
      { sigle: 'A2A', nom: 'Agent2Agent', def: "Protocole ouvert lancé par Google en avril 2025 permettant à des agents IA de fournisseurs différents de se découvrir, s'authentifier et se déléguer des tâches. Confié à la Linux Foundation en juin 2025." },
      { sigle: 'x402', nom: 'HTTP 402 Payment', def: "Standard ouvert de Coinbase (mai 2025) incrustant un paiement en stablecoin dans la requête HTTP, sans compte ni clé d'API, en réactivant le code 402 « Payment Required »." },
      { sigle: 'AP2', nom: 'Agent Payments Protocol', def: "Protocole de paiement agentique de Google (2025) ; x402 en est le facilitateur stablecoin. Orchestre l'autorisation et le règlement d'achats initiés par des agents." },
      { sigle: 'ACP', nom: 'Agentic Commerce Protocol', def: "Protocole co-développé par OpenAI et Stripe (septembre 2025), socle du Instant Checkout de ChatGPT pour des achats initiés par un agent." },
      { sigle: 'CBDC', nom: 'Central Bank Digital Currency', def: "Monnaie numérique de banque centrale. L'euro numérique de la BCE en est l'exemple européen, visant une première émission potentielle en 2029." },
      { sigle: 'wCBDC', nom: 'Wholesale CBDC', def: "Monnaie numérique de banque centrale de gros, réservée au règlement interbancaire et aux infrastructures de marché, par opposition à la CBDC de détail destinée au public. Sert d'actif de règlement sur les plateformes tokenisées, comme dans le Projet Hangang." },
      { sigle: 'Grand livre unifié', nom: 'Unified ledger', def: "Concept formalisé par la BIS en 2023 : une plateforme programmable unique où coexistent monnaie de banque centrale tokenisée, dépôts bancaires tokenisés et actifs tokenisés. Permet le règlement atomique tout en préservant le système monétaire à deux niveaux." },
      { sigle: 'Règlement atomique', nom: 'Atomic settlement', def: "Exécution indivisible d'une transaction où toutes les jambes aboutissent ou aucune. Sur un grand livre unifié, message, compensation et règlement s'effondrent en une seule étape, éliminant le risque de règlement partiel et de contrepartie." },
      { sigle: 'PPSI', nom: 'Permitted Payment Stablecoin Issuer', def: "Émetteur agréé de stablecoin de paiement au sens du GENIUS Act. Seul un PPSI peut émettre légalement aux États-Unis : filiale de banque assurée, émetteur non bancaire agréé par l'OCC, ou émetteur agréé au niveau d'un État.", guide: '/guides/qui-applique-le-genius-act/' },
    ],
  },
  {
    titre: 'Énergie & géopolitique',
    accent: 'var(--color-amber)',
    entries: [
      { sigle: 'WTI', nom: 'West Texas Intermediate', def: "Pétrole brut de référence américain, coté à New York. Avec le Brent, l'un des deux prix de référence mondiaux.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'Brent', nom: 'Brent Crude', def: "Pétrole brut de référence mondial, issu de la mer du Nord et coté à Londres. Avec le WTI, l'un des deux prix de référence du marché pétrolier.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'Cushing', nom: 'Cushing (Oklahoma)', def: "Terminal de stockage et de raccordement de pipelines du centre des États-Unis, avec une capacité d'environ 76 millions de barils. C'est le point de livraison physique du contrat à terme WTI : le prix du WTI est, littéralement, le prix du brut à Cushing. Ses stocks hebdomadaires, publiés par l'EIA, servent de baromètre de tension du marché américain. Le niveau plancher d'exploitation, sous lequel pipelines et transferts entre cuves deviennent difficiles, est estimé autour de 20 millions de barils.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'Contango', nom: 'Contango (report)', def: "Configuration de la courbe à terme où le prix pour livraison lointaine est supérieur au prix comptant. Signale un marché bien approvisionné : il rémunère celui qui stocke le brut aujourd'hui pour le livrer plus tard. Inverse de la backwardation.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'Backwardation', nom: 'Backwardation (déport)', def: "Configuration inverse du contango : le prix comptant est supérieur au prix pour livraison lointaine. Signale un marché tendu, où l'on paie une prime pour disposer du baril tout de suite. Un écart marqué entre les échéances rapprochées (M1-M3) trahit une pénurie physique, souvent liée à des stocks bas à Cushing.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'GNL', nom: 'Gaz naturel liquéfié', def: "Gaz refroidi à l'état liquide pour le transport par méthanier. Permet d'exporter le gaz hors gazoducs." },
      { sigle: 'GPL', nom: 'Gaz de pétrole liquéfié', def: "Mélange de propane et de butane liquéfié sous pression, utilisé pour le chauffage, la cuisson et certains transports. Distinct du GNL." },
      { sigle: 'Chokepoint', nom: 'Point de passage stratégique', def: "Passage maritime étroit par lequel transite une part majeure d'un flux mondial : Ormuz (pétrole, GNL), Malacca, Suez, Panama, Bab el-Mandeb. Sa concentration crée une grande efficacité en temps normal et une vulnérabilité aiguë en cas de blocage, faute de contournement à la hauteur." },
      { sigle: 'TTF', nom: 'Title Transfer Facility', def: "Marché de gros néerlandais du gaz naturel, prix de référence du gaz en Europe, coté en euros par mégawattheure. Le GNL y fixe souvent le prix marginal, ce qui rend le TTF très sensible aux ruptures d'approvisionnement, comme lors de la crise d'Ormuz de 2026.", guide: '/guides/lire-le-marche-du-gaz-et-du-gnl/' },
      { sigle: 'Henry Hub', nom: 'Henry Hub', def: "Point de livraison physique du gaz naturel en Louisiane, référence des prix du gaz aux États-Unis et de la plupart des contrats d'export de GNL américain. Coté en dollars par MMBtu, il est structurellement le moins cher des trois grands indices mondiaux.", guide: '/guides/lire-le-marche-du-gaz-et-du-gnl/' },
      { sigle: 'JKM', nom: 'Japan-Korea Marker', def: "Indice de référence du GNL spot livré en Asie du Nord-Est, publié par S&P Global Platts, coté en dollars par MMBtu. Son écart avec le TTF européen commande la direction des cargaisons entre les deux bassins.", guide: '/guides/lire-le-marche-du-gaz-et-du-gnl/' },
      { sigle: 'MMBtu', nom: 'Million British thermal units', def: "Unité d'énergie de référence du marché gazier mondial, égale à un million de BTU, soit environ 293 kWh ou 0,293 MWh. Henry Hub et JKM se cotent en dollars par MMBtu, le TTF en euros par MWh, d'où la nécessité de convertir pour comparer les trois indices." },
      { sigle: 'VLSFO', nom: 'Very Low Sulphur Fuel Oil', def: "Fioul marin à très basse teneur en soufre (moins de 0,5 %) imposé aux navires depuis la norme OMI 2020. Son prix, indexé sur le pétrole, pèse directement sur le coût des soutes, donc du fret maritime." },
      { sigle: 'U3O8', nom: 'Octoxyde de triuranium (yellowcake)', def: "Forme concentrée de l'uranium issue de la mine, le « yellowcake », unité de référence du marché. Le prix de l'uranium se cote en dollars par livre d'U3O8, au comptant et surtout à long terme (contrats des exploitants de réacteurs).", guide: '/guides/lire-le-marche-de-l-uranium/' },
      { sigle: 'UF6', nom: 'Hexafluorure d\'uranium', def: "Composé obtenu en convertissant l'oxyde d'uranium, gazeux une fois chauffé, seule forme exploitable par les usines d'enrichissement. La conversion est une étape distincte du cycle du combustible, avec son propre marché et ses propres goulots.", guide: '/guides/lire-le-marche-de-l-uranium/' },
      { sigle: 'SWU', nom: 'Separative Work Unit', def: "Unité de travail de séparation, mesurant l'effort d'enrichissement nécessaire pour augmenter la teneur en uranium 235. Le marché de l'enrichissement se compte en SWU ; la Russie en concentre une large part de la capacité mondiale.", guide: '/guides/lire-le-marche-de-l-uranium/' },
      { sigle: 'HALEU', nom: 'High-Assay Low-Enriched Uranium', def: "Uranium faiblement enrichi à haute teneur, entre 5 et 20 % d'uranium 235, combustible requis par la plupart des petits réacteurs modulaires et réacteurs avancés. Longtemps fourni commercialement par la seule Russie, il constitue le principal goulot de la relance nucléaire occidentale.", guide: '/guides/lire-le-marche-de-l-uranium/' },
      { sigle: 'SMR', nom: 'Small Modular Reactor', def: "Petit réacteur modulaire de faible puissance, conçu pour être fabriqué en série et déployé plus vite qu'une grande centrale. Au cœur des projets d'alimentation des centres de données d'IA, mais dont les premiers exemplaires commerciaux ne sont pas attendus avant le début des années 2030.", guide: '/guides/lire-le-marche-de-l-uranium/' },
      { sigle: 'OPEP', nom: 'Organisation des pays exportateurs de pétrole', def: "Cartel de producteurs (Arabie saoudite, etc.) qui coordonne les quotas de production pour influencer le prix du baril.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'OPEP+', nom: 'OPEP élargie', def: "OPEP augmentée d'une dizaine de producteurs non membres, dont la Russie, coordonnant leurs quotas depuis fin 2016. Ses décisions pèsent aujourd'hui autant que celles de l'OPEP seule : le groupe a relevé sa production de près de 600 000 barils par jour entre avril et juin 2026, puis de 188 000 supplémentaires en juillet.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'SPR', nom: 'Réserve stratégique de pétrole', def: "Stock de brut constitué par un État pour amortir une rupture d'approvisionnement. La réserve chinoise, estimée à environ 1,24 milliard de barils début 2026 (stocks commerciaux et stratégiques confondus), serait la première du monde, devant les États-Unis et le Japon. Pékin n'en publie pas le détail ; les analystes la reconstituent via les flux d'import et le suivi satellitaire des cuves.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'Stockage flottant', nom: 'Floating storage', def: "Pétrole conservé à bord de tankers à l'ancre plutôt qu'à terre, faute de cuves disponibles, parce que le brut est sanctionné, ou quand la structure des prix rémunère l'attente. Environ 166 millions de barils de brut iranien stationnaient ainsi dans les eaux asiatiques début 2026, un stock où la Chine peut puiser sans surenchérir sur le marché ouvert.", guide: '/guides/lire-le-marche-petrolier/' },
      { sigle: 'IRGC', nom: 'Islamic Revolutionary Guard Corps', def: "Gardiens de la révolution islamique : force armée d'élite iranienne, acteur clé des tensions dans le détroit d'Ormuz." },
      { sigle: 'MOU', nom: 'Memorandum of Understanding', def: "Mémorandum d'entente : accord écrit fixant des engagements entre parties, sans toujours la force contraignante d'un traité. Exemple : le MOU USA-Iran du 17 juin 2026." },
      { sigle: 'FAO', nom: "Food and Agriculture Organization", def: "Organisation des Nations unies pour l'alimentation et l'agriculture. Référence sur les prix alimentaires mondiaux et la sécurité alimentaire." },
      { sigle: 'WFP', nom: 'World Food Programme', def: "Programme alimentaire mondial de l'ONU, en charge de l'aide alimentaire d'urgence." },
      { sigle: 'PNUD', nom: 'Programme des Nations unies pour le développement', def: "Agence de l'ONU pilotant l'aide au développement ; publie des estimations sur la pauvreté et l'impact économique des crises." },
    ],
  },
  {
    titre: 'Régulation & institutions US',
    accent: '#7aa2f7',
    entries: [
      { sigle: 'SEC', nom: 'Securities and Exchange Commission', def: "Gendarme boursier américain. Supervise les marchés, les introductions en bourse et les obligations de transparence des sociétés cotées." },
      { sigle: 'Basis trade', nom: 'Arbitrage de base sur Treasuries', def: "Arbitrage à effet de levier qui capte l'écart de prix entre une obligation du Trésor au comptant et son contrat à terme : achat du titre au comptant, vente du futures, financement en repo. Apporte de la liquidité en temps normal, amplifie le stress en cas de débouclage forcé." },
      { sigle: 'Swap de taux', nom: 'Interest rate swap (IRS)', def: "Contrat par lequel deux parties échangent des flux d'intérêts sur un même capital de référence, le notionnel : l'une paie un taux fixe, l'autre un taux variable indexé sur un taux de marché comme le SOFR. Le capital n'est jamais échangé, seuls les intérêts le sont. Outil central de couverture du risque de taux, et plus grand marché de dérivés du monde.", guide: '/guides/lire-les-swaps-de-taux/' },
      { sigle: 'OIS', nom: 'Overnight Index Swap', def: "Swap dont la jambe variable est indexée sur un taux au jour le jour composé, le SOFR aux États-Unis. Ses cotations reflètent la trajectoire anticipée du taux directeur, ce qui en fait la référence pour lire les paris du marché sur la banque centrale, et le taux d'actualisation « sans risque » des dérivés.", guide: '/guides/lire-les-swaps-de-taux/' },
      { sigle: 'LIBOR', nom: 'London Interbank Offered Rate', def: "Ancien taux de référence interbancaire, calculé par sondage déclaratif et miné par un scandale de manipulation. Abandonné pour le dollar fin juin 2023 au profit du SOFR, adossé à des transactions réelles. Sa disparition a refondé tout l'édifice des swaps de taux.", guide: '/guides/lire-les-swaps-de-taux/' },
      { sigle: 'Notionnel', nom: 'Capital notionnel', def: "Montant de référence sur lequel sont calculés les flux d'un dérivé, sans être lui-même échangé. Le notionnel gonfle les statistiques de taille des marchés de dérivés, mais surestime largement le risque réel, qui ne porte que sur les flux nets et la valeur de marché.", guide: '/guides/lire-les-swaps-de-taux/' },
      { sigle: 'Swap spread', nom: 'Spread de swap', def: "Écart entre le taux d'un swap de taux d'intérêt et le rendement de l'obligation d'État de même maturité. L'arbitrage de spread de swap, cousin du basis trade, parie avec levier sur le resserrement ou l'écartement de cet écart. Environ 60 milliards de dollars s'en sont dénoués brutalement en avril 2025, un rappel de sa fragilité.", guide: '/guides/lire-les-swaps-de-taux/' },
      { sigle: 'FICC', nom: 'Fixed Income Clearing Corporation', def: "Chambre de compensation des titres à revenu fixe américains, filiale de la DTCC. Longtemps seule contrepartie centrale agréée pour les Treasuries, avant l'arrivée de CME et ICE. Au cœur du mandat de compensation obligatoire de la SEC." },
      { sigle: 'CCP', nom: 'Central Counterparty (contrepartie centrale)', def: "Chambre de compensation qui s'interpose entre acheteur et vendeur, devenant contrepartie de chaque transaction. Réduit le risque de contrepartie et organise la gestion de défaut, au prix d'appels de marge plus systématiques." },
      { sigle: 'COT', nom: 'Commitments of Traders', def: "Relevé hebdomadaire de la CFTC détaillant, par catégorie d'intervenant, les positions ouvertes sur les marchés à terme américains. Publié le vendredi à 15 h 30 heure de New York, sur données arrêtées au mardi précédent, soit un décalage de trois jours." },
      { sigle: 'Future', nom: 'Contrat à terme', def: "Contrat standardisé d'achat ou de vente d'un actif à une date future et un prix fixé d'avance, négocié sur un marché organisé. Sert à se couvrir ou à spéculer. Le positionnement sur ces contrats est ce que mesure le COT." },
      { sigle: 'Open interest', nom: 'Position ouverte', def: "Nombre total de contrats à terme ouverts et non encore dénoués à un instant donné. Le total des positions longues y égale toujours le total des positions courtes. Masse que le COT répartit entre catégories de traders." },
      { sigle: 'Option', nom: 'Option (call / put)', def: "Contrat donnant le droit, non l'obligation, d'acheter (call) ou de vendre (put) un actif à un prix fixé jusqu'à une échéance. L'acheteur paie une prime ; le vendeur l'encaisse et supporte le risque. Le comportement de couverture des vendeurs d'options, souvent des teneurs de marché, influence fortement le sous-jacent.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'Delta', nom: 'Delta', def: "Sensibilité du prix d'une option à une variation du sous-jacent : un delta de 0,5 signifie que l'option gagne 0,50 pour un mouvement de 1 du sous-jacent. Les teneurs de marché neutralisent leur delta en achetant ou vendant le sous-jacent, d'où des flux de couverture mécaniques.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'Gamma', nom: 'Gamma', def: "Vitesse à laquelle le delta d'une option change quand le sous-jacent bouge. Maximal près du prix d'exercice et à l'approche de l'échéance. Un gamma élevé oblige les teneurs de marché à réajuster sans cesse leur couverture, ce qui peut amortir ou amplifier les mouvements selon le sens de leur position.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'GEX', nom: 'Gamma Exposure', def: "Estimation du gamma net que les teneurs de marché doivent couvrir sur un indice. Un GEX positif (dealers longs gamma) tend à étouffer la volatilité ; un GEX négatif (dealers courts gamma) l'amplifie. Le niveau où il bascule, le « gamma flip », est un repère suivi de près.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: '0DTE', nom: 'Zero Days to Expiration', def: "Options qui expirent le jour même. Leur essor en a fait une part majeure du volume d'options sur le S&P 500, de l'ordre de 40 à 50 %. Leur gamma très concentré force une couverture des dealers en temps réel, devenue un moteur dominant des mouvements intrajournaliers.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'Teneur de marché', nom: 'Market maker', def: "Intermédiaire qui cote en continu des prix d'achat et de vente et se tient prêt à prendre l'autre côté des transactions. Sur les options, il vend souvent au public et couvre son exposition dans le sous-jacent, transformant les flux d'options en flux mécaniques sur l'actif lui-même.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'Put/call ratio', nom: 'Ratio put/call', def: "Rapport entre le volume, ou la position ouverte, des puts et des calls. Au-dessus de 1, les paris baissiers dominent ; en dessous, les paris haussiers. Indicateur de sentiment, à manier avec prudence : un volume élevé ne dit pas dans quel sens les dealers sont positionnés.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'Gamma squeeze', nom: 'Compression par le gamma', def: "Spirale haussière où des achats massifs de calls forcent les teneurs de marché à acheter le sous-jacent pour se couvrir, ce qui pousse le prix, ce qui les oblige à acheter encore. Mécanisme au cœur de l'épisode GameStop de janvier 2021.", guide: '/guides/lire-le-gamma-des-dealers/' },
      { sigle: 'CFTC', nom: 'Commodity Futures Trading Commission', def: "Régulateur américain des marchés de dérivés et de matières premières. Publie le rapport de positionnement « Commitment of Traders »." },
      { sigle: 'OFAC', nom: 'Office of Foreign Assets Control', def: "Bureau du Trésor américain chargé d'appliquer les sanctions économiques (gel d'avoirs, listes noires).", guide: '/guides/ofac-sdn-list/' },
      { sigle: 'SDN List', nom: 'Specially Designated Nationals and Blocked Persons List', def: "Liste de l'OFAC recensant les personnes et entités avec lesquelles tout ressortissant américain a interdiction de traiter, et dont les avoirs sous juridiction américaine sont gelés.", guide: '/guides/ofac-sdn-list/' },
      { sigle: 'IEEPA', nom: 'International Emergency Economic Powers Act', def: "Loi américaine de 1977 servant de base juridique à de nombreuses sanctions. En 2024-2025, les tribunaux ont jugé qu'elle ne permet pas de sanctionner des contrats intelligents immuables (affaire Tornado Cash)." },
      { sigle: 'Contrôle export', nom: 'Export control', def: "Restriction administrative imposée à l'exportation de biens, logiciels ou technologies sensibles. Dans les semi-conducteurs, il vise notamment les puces de calcul avancé, les équipements de fabrication, les logiciels de conception et certains usages militaires ou de supercalcul." },
      { sigle: '13F', nom: 'Formulaire 13F', def: "Déclaration trimestrielle imposée par la SEC aux gérants institutionnels exerçant un pouvoir de décision sur plus de 100 millions de dollars de titres américains éligibles. Liste leurs positions longues, avec jusqu'à 45 jours de retard.", guide: '/guides/analyser-13f-sec/' },
      { sigle: 'Form 4', nom: 'Statement of Changes in Beneficial Ownership', def: "Déclaration SEC des transactions d'initiés (dirigeants, administrateurs, actionnaires à plus de 10 %), à déposer dans les deux jours ouvrés. Donnée directionnelle et bien plus fraîche que le 13F.", guide: '/guides/analyser-form-4-sec/' },
      { sigle: '13D', nom: 'Schedule 13D', def: "Déclaration SEC de franchissement de 5 % du capital avec intention d'influence ou de contrôle. Formulaire long de l'activiste ; sa rubrique 4 expose les projets visant la société.", guide: '/guides/13d-vs-13g-sec/' },
      { sigle: '13G', nom: 'Schedule 13G', def: "Version courte du 13D, réservée aux détenteurs passifs et aux institutionnels qualifiés au-delà de 5 % du capital. Le passage du 13G au 13D signale un passage à l'action.", guide: '/guides/13d-vs-13g-sec/' },
      { sigle: '10-K', nom: 'Formulaire 10-K', def: "Rapport annuel d'une société cotée américaine déposé auprès de la SEC : activité, facteurs de risque, comptes audités et discussion de la direction. Le document public le plus complet sur une entreprise.", guide: '/guides/lire-le-10-k-sec/' },
      { sigle: 'EDGAR', nom: 'Electronic Data Gathering, Analysis, and Retrieval', def: "Base de données publique de la SEC où sont déposés tous les documents réglementaires (10-K, 13F, S-1)." },
      { sigle: 'BLS', nom: 'Bureau of Labor Statistics', def: "Agence statistique américaine du travail. Publie le CPI, l'emploi, et les indices de prix import/export." },
      { sigle: 'CLARITY', nom: 'CLARITY Act', def: "Projet de loi américain visant à clarifier la répartition de la régulation crypto entre SEC et CFTC." },
      { sigle: 'GENIUS', nom: 'GENIUS Act', def: "Loi fédérale américaine sur les stablecoins de paiement, promulguée le 18 juillet 2025 : réserves intégrales, émetteurs agréés, audits.", guide: '/guides/stablecoins-genius-act/' },
      { sigle: 'NASAA', nom: 'North American Securities Administrators Association', def: "Association des régulateurs boursiers des États américains, du Canada et du Mexique." },
      { sigle: 'USAID', nom: 'U.S. Agency for International Development', def: "Agence américaine pour le développement international, en charge de l'aide étrangère." },
      { sigle: 'SWIFT', nom: 'Society for Worldwide Interbank Financial Telecommunication', def: "Réseau de messagerie interbancaire mondial pour les transferts. Exclure un pays de SWIFT est une arme de sanction majeure." },
      { sigle: 'CIPS', nom: 'Cross-Border Interbank Payment System', def: "Système de paiement transfrontalier chinois, présenté comme une alternative à SWIFT." },
      { sigle: 'FSOC', nom: 'Financial Stability Oversight Council', def: "Conseil américain de supervision de la stabilité financière. Peut désigner des non-banques comme systémiques." },
      { sigle: 'OFR', nom: 'Office of Financial Research', def: "Bureau de recherche financière rattaché au Trésor américain. Produit données et analyses sur les risques systémiques." },
      { sigle: 'Form PF', nom: 'Private Fund (formulaire de reporting SEC)', def: "Formulaire de reporting confidentiel des fonds privés à la SEC. Principale source de données réglementaires sur leur levier et leurs contreparties." },
      { sigle: 'CET1', nom: 'Common Equity Tier 1', def: "Ratio de fonds propres durs des banques rapportés aux actifs pondérés du risque. Mesure centrale de leur solvabilité." },
      { sigle: 'DFAST', nom: 'Dodd-Frank Act Stress Test', def: "Volet quantitatif du test de résistance annuel de la Fed, issu de la loi Dodd-Frank : la banque survivrait-elle à une récession sévère en gardant ses fonds propres au-dessus des minimums ? La Fed projette pertes, revenus et ratio CET1 sur neuf trimestres.", guide: '/guides/lire-un-stress-test-bancaire/' },
      { sigle: 'CCAR', nom: 'Comprehensive Capital Analysis and Review', def: "Volet du test de résistance de la Fed portant sur la planification du capital : la banque peut-elle verser dividendes et rachats d'actions tout en restant solide sous stress ? Adossé au DFAST, il en tire le coussin de fonds propres de stress (SCB).", guide: '/guides/lire-un-stress-test-bancaire/' },
      { sigle: 'SCB', nom: 'Stress Capital Buffer', def: "Coussin de fonds propres de stress : exigence de capital propre à chaque banque, calculée à partir du test de résistance (ponction de CET1 sous le scénario adverse, plus les dividendes prévus), avec un plancher de 2,5 %. Il détermine la marge dont dispose la banque pour rendre du capital à ses actionnaires.", guide: '/guides/lire-un-stress-test-bancaire/' },
      { sigle: 'PPNR', nom: 'Pre-Provision Net Revenue', def: "Revenu net avant provisions : ce qu'une banque gagne avant de passer des provisions pour pertes. Dans un test de résistance, c'est le premier coussin qui absorbe les pertes avant que le capital ne soit entamé ; un PPNR solide protège le CET1.", guide: '/guides/lire-un-stress-test-bancaire/' },
      { sigle: 'LCR', nom: 'Liquidity Coverage Ratio', def: "Ratio de liquidité à court terme issu de Bâle III, en vigueur aux États-Unis depuis 2015. Impose aux grandes banques de détenir assez d'actifs liquides de haute qualité (HQLA) pour couvrir leurs sorties nettes de trésorerie sur un scénario de stress de 30 jours. Doit rester au-dessus de 100 %. Cible du chantier de réforme 2026." },
      { sigle: 'HQLA', nom: 'High-Quality Liquid Assets', def: "Actifs liquides de haute qualité éligibles au numérateur du LCR : réserves à la banque centrale et Treasuries (niveau 1, sans décote), puis dette d'agence et certains titres notés, avec décotes. Les banques en détiennent souvent bien au-delà du minimum, ce que les régulateurs qualifient en 2026 de thésaurisation de liquidité." },
      { sigle: 'NSFR', nom: 'Net Stable Funding Ratio', def: "Ratio de financement stable net, complément du LCR sur un horizon d'un an. Vise à limiter la dépendance des banques aux financements de gros à court terme en exigeant un adossement entre la stabilité de leurs ressources et la liquidité de leurs actifs." },
      { sigle: 'Bâle III', nom: 'Accords de Bâle III', def: "Cadre prudentiel international adopté après la crise de 2008 par le Comité de Bâle, imposant aux banques des minimums de fonds propres (CET1 à 4,5 % des actifs pondérés du risque, plus des coussins), de liquidité (LCR) et de financement stable (NSFR). Sa dernière étape, le « Bâle III endgame », a fait l'objet d'une re-proposition américaine allégée en mars 2026.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'APR', nom: 'Actifs pondérés du risque', def: "Risk-weighted assets : total des actifs d'une banque pondérés selon leur risque estimé, un prêt risqué comptant davantage qu'une obligation d'État. Dénominateur des ratios de fonds propres comme le CET1 ; leur mode de calcul, plus ou moins favorable, est un enjeu central des accords de Bâle.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'AOCI', nom: 'Accumulated Other Comprehensive Income', def: "Poste des fonds propres qui accumule certains gains et pertes latents, dont ceux sur les titres classés disponibles à la vente (AFS). Les plus grandes banques doivent l'inclure dans leur CET1 ; une dérogation a longtemps permis à d'autres de l'en exclure, masquant des pertes latentes comme chez SVB. La réforme américaine de 2026 étend son intégration.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'HTM / AFS', nom: 'Held-to-Maturity / Available-for-Sale', def: "Deux modes de comptabilisation des titres d'une banque. Les titres détenus jusqu'à l'échéance (HTM) sont inscrits au coût, leurs pertes latentes restant invisibles au bilan ; les titres disponibles à la vente (AFS) sont réévalués au prix de marché via l'AOCI. Classer en HTM permet de dissimuler des moins-values tant qu'on ne vend pas, le piège fatal à SVB.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'Ratio de levier', nom: 'Leverage ratio', def: "Fonds propres de base (Tier 1) rapportés au total des expositions, sans pondération par le risque. Garde-fou contre une sous-estimation du risque par les modèles internes des banques. Sa version renforcée pour les grandes banques américaines, le SLR, est fixée à 5 %.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'SLR', nom: 'Supplementary Leverage Ratio', def: "Ratio de levier supplémentaire américain : fonds propres Tier 1 rapportés à la totalité des expositions, Treasuries et réserves compris, sans pondération du risque. Sa version renforcée pour les banques systémiques, l'eSLR, exigeait un coussin fixe de 2 %. La réforme finalisée fin 2025 le recalibre à la moitié de la surcharge G-SIB, pour qu'il redevienne un filet de sécurité plutôt qu'une contrainte mordante, notamment sur l'intermédiation du marché des Treasuries.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'RBC', nom: 'Risk-Based Capital', def: "Capital réglementaire minimal d'un assureur américain, calculé selon la taille et le risque de ses actifs et engagements. Le ratio RBC rapporte le capital ajusté total au seuil de contrôle autorisé (ACL) ; la NAIC déclenche des actions graduées quand il descend sous 200 %, puis 150 %, 100 % et 70 %. L'équivalent, pour l'assurance, du CET1 bancaire.", guide: '/guides/lire-la-solidite-d-un-assureur-vie/' },
      { sigle: 'G-SIB', nom: 'Global Systemically Important Bank', def: "Banque d'importance systémique mondiale, désignée par le Conseil de stabilité financière. Soumise à une surcharge de fonds propres proportionnelle à son poids systémique, en plus des minimums de Bâle, pour réduire le risque qu'elle soit trop grosse pour faire faillite.", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'MNI', nom: 'Net interest margin', def: "Marge nette d'intérêt : écart entre ce qu'une banque gagne sur ses prêts et titres et ce qu'elle paie sur ses dépôts et financements, rapporté à ses actifs productifs. Cœur du modèle de banque de détail et métrique la plus scrutée des résultats, souvent plus révélatrice que le bénéfice par action. Le revenu correspondant est le produit net d'intérêts (net interest income, NII).", guide: '/guides/lire-la-solidite-d-une-banque/' },
      { sigle: 'LDI', nom: 'Liability-driven investment', def: "Stratégie de fonds de pension qui utilise obligations longues et dérivés pour aligner les actifs sur les engagements futurs. Au Royaume-Uni, la crise de 2022 a montré qu'un choc de taux pouvait déclencher appels de marge et ventes forcées de gilts." },
      { sigle: 'FDIC', nom: 'Federal Deposit Insurance Corporation', def: "Agence fédérale qui garantit les dépôts bancaires américains jusqu'à 250 000 dollars par déposant et par banque, et qui agit comme administratrice des banques en faillite. Elle a saisi et cédé SVB, Signature et First Republic en 2023." },
      { sigle: 'OCC', nom: 'Office of the Comptroller of the Currency', def: "Régulateur bancaire fédéral américain qui agrée et supervise les banques nationales. Sous le GENIUS Act, il est le régulateur principal des émetteurs de stablecoins non bancaires fédéraux et des banques nationales, au périmètre le plus large.", guide: '/guides/qui-applique-le-genius-act/' },
      { sigle: 'NCUA', nom: 'National Credit Union Administration', def: "Agence fédérale qui agrée et supervise les credit unions américaines et garantit leurs dépôts. Sous le GENIUS Act, elle régule les émetteurs de stablecoins adossés à une credit union." },
      { sigle: 'FinCEN', nom: 'Financial Crimes Enforcement Network', def: "Cellule de renseignement financier du Trésor américain, chargée de la lutte anti-blanchiment. Sous le GENIUS Act, elle traite les émetteurs agréés comme des institutions financières soumises au Bank Secrecy Act.", guide: '/guides/qui-applique-le-genius-act/' },
      { sigle: 'BSA', nom: 'Bank Secrecy Act', def: "Loi américaine de 1970, socle de la lutte anti-blanchiment. Impose aux institutions financières des programmes de vigilance, d'identification de la clientèle et de déclaration d'opérations suspectes. Le GENIUS Act y assujettit les émetteurs de stablecoins agréés.", guide: '/guides/qui-applique-le-genius-act/' },
    ],
  },
];

export interface GlossaryEntry extends GlossarySourceEntry {
  slug: string;
  url: string;
  sectionTitle: string;
  sectionSlug: string;
  accent: string;
  atlas?: GlossaryKnowledgeGraph;
}

export const slugifyGlossary = (s: string) =>
  s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

export const glossaryUpdatedIso = '2026-07-16';

const seenSlugs = new Map<string, number>();
const uniqueSlug = (value: string) => {
  const base = slugifyGlossary(value) || 'terme';
  const n = (seenSlugs.get(base) ?? 0) + 1;
  seenSlugs.set(base, n);
  return n === 1 ? base : `${base}-${n}`;
};

